'use client';

import React, { useEffect, useState } from 'react';
import Image from 'next/image';
import { Card, CardContent, CardHeader, CardTitle } from '@/shared/components/ui/card';
import { Button } from '@/shared/components/ui/button';
import useRequireAuth from '@/features/auth/hooks/useRequireAuth';
import { Camera, User, Award } from 'lucide-react';
import { userService } from '@/features/profile/services/userService';
import { useRouter } from 'next/navigation';

// Local shape used by this form ΓÇö keep it lightweight and decoupled from
// backend DTOs to avoid tight coupling with server types.
interface LocalUserProfile {
  name: string;
  email: string;
  bio?: string;
  specialization?: string;
  year?: string;
  institution?: string;
  location?: string;
  phone?: string;
  avatar?: string | null;
}

interface ValidationError {
  field?: string;
  property?: string;
  name?: string;
  errors?: string[] | Record<string, string>;
  constraints?: Record<string, string>;
  messages?: string[];
}

// Type guard to check for a specific error structure
function isBackendError(
  error: unknown
): error is { response: { data: { message: string | string[]; errors: ValidationError[] } } } {
  return (
    error !== null &&
    typeof error === 'object' &&
    'response' in error &&
    error.response !== null &&
    typeof error.response === 'object' &&
    'data' in error.response &&
    error.response.data !== null &&
    typeof error.response.data === 'object'
  );
}

export default function EditProfilePage() {
  const { isLoading, session } = useRequireAuth();
  const router = useRouter();

  const [profile, setProfile] = useState<LocalUserProfile>({
    name: '',
    email: '',
    bio: '',
    specialization: '',
    year: '',
    institution: '',
    location: '',
    phone: '',
    avatar: null,
  });

  const [isSaving, setIsSaving] = useState(false);
  const [saveMessage, setSaveMessage] = useState('');
  const [fieldErrors, setFieldErrors] = useState<Record<string, string[]>>({});
  const [previewImage, setPreviewImage] = useState<string | null>(null);

  useEffect(() => {
    const fetchProfile = async () => {
      if (session?.user?.id) {
        try {
          const userProfile = await userService.getUserProfile(session.user.id);
          if (!userProfile) {
            setSaveMessage('Profile data not found');
            return;
          }
          const firstName = userProfile.firstName || '';
          const lastName = userProfile.lastName || '';
          // Compose name, trim to avoid ' '
          const name = (firstName + ' ' + lastName).trim();
          setProfile({
            name,
            email: userProfile.email || '',
            bio: userProfile.bio || '',
            specialization: userProfile.specialization || '',
            year: userProfile.yearOfExperience ? String(userProfile.yearOfExperience) : '',
            institution: userProfile.institution || '',
            location: userProfile.location || '',
            phone: userProfile.phone || '',
            avatar: userProfile.profileImage || null, // Use profileImage from backend
          });
          setPreviewImage(userProfile.profileImage || null);
        } catch (error: unknown) {
          // Log extra details only in development to avoid noisy logs in prod
          if (process.env.NODE_ENV !== 'production') {
            console.error('Error fetching profile:', error);
          }
          setSaveMessage('Error fetching profile');
        }
      }
    };

    fetchProfile();
  }, [session]);

  const handleChange = (
    e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement | HTMLSelectElement>
  ) => {
    const { name, value } = e.target;
    setProfile(prev => ({ ...prev, [name]: value }));
    // Clear field-level errors for this UI field when user edits it
    setFieldErrors(prev => {
      const copy = { ...prev };
      delete copy[name];
      return copy;
    });
  };

  const handleImageChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setPreviewImage(reader.result as string);
        // Optionally, update profile.avatar here if you want to send it to the backend immediately or on save
        setProfile(prev => ({ ...prev, avatar: reader.result as string }));
      };
      reader.readAsDataURL(file);
    }
  };

  const handleSaveProfile = async () => {
    setIsSaving(true);
    setSaveMessage('');

    try {
      if (!session?.user?.id) {
        setSaveMessage('Error: User not authenticated');
        return;
      }

      const nameParts = profile.name.trim().split(' ');
      const firstName = nameParts.shift() || '';
      const lastName = nameParts.join(' ') || '';

      // Map to backend UpdateUserDto expected fields
      const updatePayload: Record<string, string | number | undefined> = {
        firstName,
        lastName,
        bio: profile.bio || undefined,
        location: profile.location || undefined,
        phone: profile.phone || undefined,
        profileImage: profile.avatar || undefined, // Send avatar as profileImage
        institution: profile.institution || undefined,
        specialization: profile.specialization || undefined,
        yearOfExperience: profile.year ? Number(profile.year) : undefined,
      };

      await userService.updateUserProfile(session.user.id, updatePayload);

      setSaveMessage('Profile saved successfully');
      setFieldErrors({});
      setTimeout(() => setSaveMessage(''), 3000);
      router.push('/profile'); // Redirect back to display page
    } catch (error: unknown) {
      // Try to surface server validation errors if available
      let friendly = 'Error saving profile';
      if (isBackendError(error)) {
        const resp = error.response.data;
        // Common NestJS/axios shapes: { message: '...', statusCode: 400 } or { message: ['a','b'] }
        if (Array.isArray(resp.message)) {
          friendly = resp.message.join('; ');
        } else if (typeof resp.message === 'string') {
          friendly = resp.message;
        } else if (resp.errors) {
          // Validation pipe may return an object with constraints
          try {
            // resp.errors from our backend is an array of { field, errors: [] }
            if (Array.isArray(resp.errors)) {
              const byField: Record<string, string[]> = {};
              resp.errors.forEach(err => {
                const field = err.field || err.property || err.name || 'general';
                const errs = err.errors || err.constraints || err.messages || [];
                byField[field] = Array.isArray(errs) ? errs : [String(errs)];
              });

              // Map backend field names to our UI input names (e.g., firstName/lastName -> name)
              const mapField = (backendField: string) => {
                if (!backendField) return backendField;
                if (['firstName', 'lastName'].includes(backendField)) return 'name';
                if (backendField === 'phoneNumber' || backendField === 'phone') return 'phone';
                if (backendField === 'profileImage') return 'avatar';
                if (backendField === 'yearOfExperience') return 'year';
                return backendField;
              };

              const uiErrors: Record<string, string[]> = {};
              Object.entries(byField).forEach(([k, v]) => {
                const uiKey = mapField(k) || k;
                uiErrors[uiKey] = (uiErrors[uiKey] || []).concat(v as string[]);
              });

              setFieldErrors(uiErrors);

              const all = Object.values(byField).flatMap(v => v as string[]);
              if (all.length) friendly = all.join('; ');
            } else {
              const all = Object.values(resp.errors || {}).flatMap(
                (v: { constraints: Record<string, string> } | unknown) =>
                  v && typeof v === 'object' && 'constraints' in v && v.constraints
                    ? Object.values(v.constraints)
                    : []
              );
              if (all.length) friendly = all.join('; ');
            }
          } catch {}
        }
      } else if (error instanceof Error) {
        friendly = error.message;
      }

      // Emit structured debug information in development only. Axios/Nest
      // error objects can be empty when stringified; include response.data
      // so developers see validation errors without exposing them in prod.
      if (process.env.NODE_ENV !== 'production') {
        console.error('Error saving profile:', error);
      }
      setSaveMessage(friendly);
    } finally {
      setIsSaving(false);
    }
  };

  if (isLoading) {
    return (
      <div className="flex items-center justify-center min-h-[80vh] bg-gray-50/50 dark:bg-slate-900/50">
        <div className="animate-spin rounded-full h-12 w-12 border-t-2 border-b-2 border-blue-500"></div>
      </div>
    );
  }

  return (
    <div className="container mx-auto px-4 py-8 bg-gray-50/50 dark:bg-slate-900/50 min-h-screen space-y-6">
      <div className="flex items-center justify-between">
        <h1 className="text-3xl font-bold text-gray-900 dark:text-white">Edit Profile</h1>
        <Button variant="outline" onClick={() => router.push('/profile')} className="dark:border-slate-700 dark:text-slate-300">
          Cancel
        </Button>
      </div>

      <Card className="bg-white/80 dark:bg-slate-800/50 backdrop-blur-sm border-gray-100 dark:border-slate-700/50">
        <CardHeader>
          <CardTitle className="flex items-center text-gray-900 dark:text-white">
            <User className="h-5 w-5 mr-2 text-blue-500" />
            Personal Information
          </CardTitle>
        </CardHeader>
        <CardContent>
          <div className="grid grid-cols-1 gap-6 md:grid-cols-2">
            <div className="md:col-span-2 flex flex-col items-center mb-4">
              <div className="relative">
                <div className="h-32 w-32 rounded-full bg-gray-100 dark:bg-slate-800 border-2 border-dashed border-gray-200 dark:border-slate-700 flex items-center justify-center text-gray-400 dark:text-slate-600 text-4xl font-bold overflow-hidden transition-all hover:border-blue-500/50">
                  {previewImage ? (
                    <Image
                      src={previewImage}
                      alt="Profile"
                      width={128}
                      height={128}
                      className="h-full w-full object-cover"
                    />
                  ) : (
                    profile.name.charAt(0) || 'U'
                  )}
                </div>
                <label
                  htmlFor="avatar-upload"
                  className="absolute bottom-0 right-0 bg-blue-500 text-white p-2 rounded-full cursor-pointer"
                >
                  <Camera className="h-4 w-4" />
                  <input
                    id="avatar-upload"
                    type="file"
                    accept="image/*"
                    className="hidden"
                    onChange={handleImageChange}
                    aria-label="Upload profile picture"
                  />
                </label>
              </div>
              <p className="text-sm text-gray-500 dark:text-slate-500 mt-3">
                Click the camera icon to upload a profile picture
              </p>
            </div>

            <div>
              <label htmlFor="name" className="block text-sm font-medium text-gray-700 dark:text-slate-300 mb-1">
                Full Name
              </label>
              <input
                type="text"
                name="name"
                className="w-full px-4 py-2 bg-white dark:bg-slate-900 border border-gray-200 dark:border-slate-700 text-gray-900 dark:text-white rounded-lg focus:ring-2 focus:ring-blue-500/20 focus:border-blue-500 transition-all outline-none"
                value={profile.name}
                onChange={handleChange}
                placeholder="Enter your full name"
              />
              {fieldErrors.name && (
                <p className="text-xs text-red-600 dark:text-red-400 mt-1">{fieldErrors.name.join('; ')}</p>
              )}
            </div>

            <div>
              <label htmlFor="email" className="block text-sm font-medium text-gray-700 dark:text-slate-300 mb-1">
                Email
              </label>
              <input
                id="email"
                type="email"
                name="email"
                className="w-full px-4 py-2 border border-gray-200 dark:border-slate-700 bg-gray-50 dark:bg-slate-800/50 text-gray-500 dark:text-slate-500 rounded-lg cursor-not-allowed"
                value={profile.email}
                readOnly
                placeholder="Your email address"
              />
              <p className="text-xs text-gray-400 dark:text-slate-600 mt-1">Email cannot be changed</p>
            </div>

            <div className="md:col-span-2">
              <label htmlFor="bio" className="block text-sm font-medium text-gray-700 dark:text-slate-300 mb-1">
                Bio
              </label>
              <textarea
                id="bio"
                name="bio"
                rows={4}
                className="w-full px-4 py-2 bg-white dark:bg-slate-900 border border-gray-200 dark:border-slate-700 text-gray-900 dark:text-white rounded-lg focus:ring-2 focus:ring-blue-500/20 focus:border-blue-500 transition-all outline-none"
                value={profile.bio}
                onChange={handleChange}
                placeholder="Tell us about yourself..."
              />
              {fieldErrors.bio && (
                <p className="text-xs text-red-600 dark:text-red-400 mt-1">{fieldErrors.bio.join('; ')}</p>
              )}
            </div>

            <div>
              <label htmlFor="phone" className="block text-sm font-medium text-gray-700 dark:text-slate-300 mb-1">
                Phone Number
              </label>
              <input
                id="phone"
                type="tel"
                name="phone"
                className="w-full px-4 py-2 bg-white dark:bg-slate-900 border border-gray-200 dark:border-slate-700 text-gray-900 dark:text-white rounded-lg focus:ring-2 focus:ring-blue-500/20 focus:border-blue-500 transition-all outline-none"
                value={profile.phone}
                onChange={handleChange}
                placeholder="Enter your phone number"
              />
              {fieldErrors.phone && (
                <p className="text-xs text-red-600 dark:text-red-400 mt-1">{fieldErrors.phone.join('; ')}</p>
              )}
            </div>

            <div>
              <label className="block text-sm font-medium text-gray-700 dark:text-slate-300 mb-1">Location</label>
              <input
                type="text"
                name="location"
                className="w-full px-4 py-2 bg-white dark:bg-slate-900 border border-gray-200 dark:border-slate-700 text-gray-900 dark:text-white rounded-lg focus:ring-2 focus:ring-blue-500/20 focus:border-blue-500 transition-all outline-none"
                value={profile.location}
                onChange={handleChange}
                placeholder="City, Country"
              />
              {fieldErrors.location && (
                <p className="text-xs text-red-600 dark:text-red-400 mt-1">{fieldErrors.location.join('; ')}</p>
              )}
            </div>
          </div>
        </CardContent>
      </Card>

      <Card className="bg-white/80 dark:bg-slate-800/50 backdrop-blur-sm border-gray-100 dark:border-slate-700/50">
        <CardHeader>
          <CardTitle className="text-gray-900 dark:text-white flex items-center gap-2">
            <Award className="h-5 w-5 text-purple-500" />
            Academic Information
          </CardTitle>
        </CardHeader>
        <CardContent>
          <div className="grid grid-cols-1 gap-6 md:grid-cols-2">
            <div>
              <label className="block text-sm font-medium text-gray-700 dark:text-slate-300 mb-1">Institution</label>
              <input
                type="text"
                name="institution"
                className="w-full px-4 py-2 bg-white dark:bg-slate-900 border border-gray-200 dark:border-slate-700 text-gray-900 dark:text-white rounded-lg focus:ring-2 focus:ring-blue-500/20 focus:border-blue-500 transition-all outline-none"
                value={profile.institution}
                onChange={handleChange}
                placeholder="University or Medical School"
              />
              {fieldErrors.institution && (
                <p className="text-xs text-red-600 dark:text-red-400 mt-1">{fieldErrors.institution.join('; ')}</p>
              )}
            </div>

            <div>
              <label htmlFor="year" className="block text-sm font-medium text-gray-700 dark:text-slate-300 mb-1">
                Year
              </label>
              <select
                id="year"
                name="year"
                className="w-full px-4 py-2 bg-white dark:bg-slate-900 border border-gray-200 dark:border-slate-700 text-gray-900 dark:text-white rounded-lg focus:ring-2 focus:ring-blue-500/20 focus:border-blue-500 transition-all outline-none"
                value={profile.year}
                onChange={handleChange}
                title="Select your current year of study"
              >
                <option value="">Select Year</option>
                <option value="1">1st Year</option>
                <option value="2">2nd Year</option>
                <option value="3">3rd Year</option>
                <option value="4">4th Year</option>
                <option value="5">5th Year</option>
                <option value="6">6th Year</option>
                <option value="resident">Resident</option>
                <option value="fellow">Fellow</option>
                <option value="attending">Attending</option>
              </select>
              {fieldErrors.year && (
                <p className="text-xs text-red-600 dark:text-red-400 mt-1">{fieldErrors.year.join('; ')}</p>
              )}
            </div>
          </div>
        </CardContent>
      </Card>

      <div className="flex justify-end">
        {saveMessage && (
          <div
            className={`mr-4 py-2 px-6 rounded-lg text-sm font-medium shadow-sm transition-all animate-in fade-in slide-in-from-top-2 ${
              saveMessage.includes('Error')
                ? 'bg-red-50 dark:bg-red-900/20 text-red-700 dark:text-red-400 border border-red-100 dark:border-red-800/50'
                : 'bg-green-50 dark:bg-green-900/20 text-green-700 dark:text-green-400 border border-green-100 dark:border-green-800/50'
            }`}
          >
            {saveMessage}
          </div>
        )}
        <Button
          variant="default"
          onClick={handleSaveProfile}
          disabled={isSaving}
          className={isSaving ? 'opacity-50 cursor-not-allowed' : ''}
        >
          {isSaving ? 'Saving...' : 'Save Profile'}
        </Button>
      </div>
    </div>
  );
}

'use client';

import React, { useEffect, useState } from 'react';
import { Card, CardContent, CardHeader, CardTitle } from '@/shared/components/ui/card';
import { Button } from '@/shared/components/ui/button';
import { User, Edit, Award, Clock, Settings } from 'lucide-react';
import useRequireAuth from '@/features/auth/hooks/useRequireAuth'; // Keep this for session management
import { userService } from '@/features/profile/services/userService';
import { useRouter } from 'next/navigation';

// Local shape used by this form ΓÇö keep it lightweight and decoupled from
// backend DTOs to avoid tight coupling with server types.
interface LocalUserProfile {
  name: string;
  email: string;
  bio?: string;
  specialization?: string;
  year?: string;
  institution?: string;
  location?: string;
  phone?: string;
  profileImage?: string | null;
  yearOfExperience?: number;
}

export default function ProfilePage() {
  const { isLoading, session } = useRequireAuth();

  const [profile, setProfile] = useState<LocalUserProfile>({
    name: '',
    email: '',
    bio: '',
    specialization: '',
    year: '',
    institution: '',
    location: '',
    phone: '',
    profileImage: null,
    yearOfExperience: undefined,
  });
  const router = useRouter(); // Initialize useRouter here

  useEffect(() => {
    const fetchProfile = async () => {
      if (session?.user?.id) {
        try {
          const userProfile = await userService.getUserProfile(session.user.id);
          if (!userProfile) {
            return;
          }
          const firstName = userProfile.firstName || '';
          const lastName = userProfile.lastName || '';
          // Compose name, trim to avoid ' '
          const name = (firstName + ' ' + lastName).trim();
          setProfile({
            name,
            email: userProfile.email || '',
            bio: userProfile.bio || '',
            specialization: userProfile.specialization || '',
            year: userProfile.yearOfExperience ? String(userProfile.yearOfExperience) : '',
            institution: userProfile.institution || '',
            location: userProfile.location || '',
            phone: userProfile.phone || '',
            profileImage: userProfile.profileImage || null,
            yearOfExperience: userProfile.yearOfExperience || undefined,
          });
        } catch (error: unknown) {
          // Log extra details only in development to avoid noisy logs in prod
          if (process.env.NODE_ENV !== 'production') {
            console.error('Error fetching profile:', error);
          }
        }
      }
    };

    fetchProfile();
  }, [session]);

  if (isLoading) {
    return (
      <div className="flex items-center justify-center min-h-[80vh] bg-gray-50/50 dark:bg-slate-900/50">
        <div className="animate-spin rounded-full h-12 w-12 border-t-2 border-b-2 border-blue-500"></div>
      </div>
    );
  }

  return (
    <div className="container mx-auto px-4 py-8 bg-gray-50/50 dark:bg-slate-900/50 min-h-screen">
      {/* Header Section */}
      <div className="mb-8 flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div className="flex items-center gap-4">
          <div className="h-16 w-16 rounded-full bg-white dark:bg-slate-800 shadow-sm border border-gray-200 dark:border-slate-700 flex items-center justify-center overflow-hidden">
            {profile.profileImage ? (
              <img src={profile.profileImage as string} alt={profile.name} className="h-full w-full object-cover" />
            ) : (
              <User className="h-8 w-8 text-gray-400 dark:text-slate-500" />
            )}
          </div>
          <div>
            <h1 className="text-3xl font-bold text-gray-900 dark:text-white">{profile.name || 'User'}</h1>
            <p className="text-gray-600 dark:text-slate-400">{profile.email}</p>
          </div>
        </div>
        <Button onClick={() => router.push('/profile/edit')} className="w-full md:w-auto">
          <Edit className="mr-2 h-4 w-4" /> Edit Profile
        </Button>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
        <Card className="bg-white/80 dark:bg-slate-800/50 backdrop-blur-sm border-gray-100 dark:border-slate-700/50">
          <CardHeader>
            <CardTitle className="flex items-center text-gray-900 dark:text-white">
              <User className="h-5 w-5 mr-3 text-blue-500" />
              Personal Information
            </CardTitle>
          </CardHeader>
          <CardContent className="space-y-6">
            <div className="grid grid-cols-1 sm:grid-cols-2 gap-6">
              <div>
                <p className="text-xs font-semibold text-gray-400 dark:text-slate-500 uppercase tracking-wider">Full Name</p>
                <p className="text-base font-medium text-gray-900 dark:text-slate-200">{profile.name || 'Not set'}</p>
              </div>
              <div>
                <p className="text-xs font-semibold text-gray-400 dark:text-slate-500 uppercase tracking-wider">Email Address</p>
                <p className="text-base font-medium text-gray-900 dark:text-slate-200">{profile.email}</p>
              </div>
              <div>
                <p className="text-xs font-semibold text-gray-400 dark:text-slate-500 uppercase tracking-wider">Phone Number</p>
                <p className="text-base font-medium text-gray-900 dark:text-slate-200">{profile.phone || 'Not set'}</p>
              </div>
              <div>
                <p className="text-xs font-semibold text-gray-400 dark:text-slate-500 uppercase tracking-wider">Location</p>
                <p className="text-base font-medium text-gray-900 dark:text-slate-200">{profile.location || 'Not set'}</p>
              </div>
            </div>
            {profile.bio && (
              <div>
                <p className="text-xs font-semibold text-gray-400 dark:text-slate-500 uppercase tracking-wider">Bio</p>
                <p className="text-sm text-gray-600 dark:text-slate-400 mt-1 leading-relaxed">{profile.bio}</p>
              </div>
            )}
          </CardContent>
        </Card>

        <Card className="bg-white/80 dark:bg-slate-800/50 backdrop-blur-sm border-gray-100 dark:border-slate-700/50">
          <CardHeader>
            <CardTitle className="flex items-center text-gray-900 dark:text-white">
              <Award className="h-5 w-5 mr-3 text-purple-500" />
              Academic Information
            </CardTitle>
          </CardHeader>
          <CardContent className="space-y-6">
            <div>
              <p className="text-xs font-semibold text-gray-400 dark:text-slate-500 uppercase tracking-wider">Institution</p>
              <p className="text-lg font-semibold text-gray-900 dark:text-slate-200">{profile.institution || 'Not specified'}</p>
            </div>
            <div className="grid grid-cols-1 sm:grid-cols-2 gap-6">
              <div>
                <p className="text-xs font-semibold text-gray-400 dark:text-slate-500 uppercase tracking-wider">Specialization</p>
                <p className="text-base font-medium text-gray-900 dark:text-slate-200">{profile.specialization || 'Not set'}</p>
              </div>
              <div>
                <p className="text-xs font-semibold text-gray-400 dark:text-slate-500 uppercase tracking-wider">Experience Level</p>
                <p className="text-base font-medium text-gray-900 dark:text-slate-200">{profile.year || 'Not set'}</p>
              </div>
            </div>
          </CardContent>
        </Card>
      </div>

      <h2 className="text-2xl font-bold mt-12 mb-6 text-gray-900 dark:text-white">Account Management</h2>
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6 mb-8">
        <Card className="hover:border-blue-500/50 transition-colors bg-white/80 dark:bg-slate-800/50 backdrop-blur-sm border-gray-100 dark:border-slate-700/50">
          <CardHeader>
