import { NextResponse } from 'next/server';
import { getServerSession } from 'next-auth/next';
import { authOptions } from '@/features/auth/services/nextauth';

export async function POST(request: Request) {
  try {
    const session = await getServerSession(authOptions);

    if (!session) {
      return NextResponse.json({ message: 'Unauthorized' }, { status: 401 });
    }

    const rawBackend =
      process.env.NEXT_PUBLIC_API_URL ||
      process.env.NEXT_PUBLIC_API_BASE_URL ||
      'http://localhost:3002';
    const backendBase = rawBackend.replace(/\/+$/g, '');
    const backendUrl = /\/v1$/i.test(backendBase) ? backendBase : `${backendBase}/v1`;

    const response = await fetch(`${backendUrl}/security/email/resend`, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        Authorization: `Bearer ${session.user.accessToken}`,
      },
    });

    const data = await response.json();

    if (!response.ok) {
      return NextResponse.json(
        {
          message: data.message || 'Failed to resend verification email',
        },
        { status: response.status }
      );
    }

    return NextResponse.json({
      message: 'Verification email sent successfully',
    });
  } catch (error) {
    console.error('Resend verification email error:', error);
    return NextResponse.json({ message: 'Failed to resend verification email' }, { status: 500 });
  }
}

import { NextRequest, NextResponse } from 'next/server';
import { AUTH_ERROR_MESSAGES, AuthErrorCode } from '@/features/auth/services/authErrors';

const BACKEND_URL = process.env.BACKEND_URL || 'http://localhost:3002';

export async function POST(request: NextRequest) {
  try {
    const loginData = await request.json();

    console.log('Forwarding login to backend:', loginData.identifier);

    const response = await fetch(`${BACKEND_URL}/v1/auth/login`, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
      },
      body: JSON.stringify(loginData),
    });

    if (!response.ok) {
      const errorData = await response.json();
      console.error('Backend login failed:', response.status, errorData);
      const errorMessage = errorData.message || 'Login failed';
      return NextResponse.json({ message: errorMessage, errors: errorData.errors }, { status: response.status });
    }

    const data = await response.json();
    return NextResponse.json(data, { status: 200 });
  } catch (error) {
    console.error('Login proxy error:', error);
    return NextResponse.json({ message: 'Internal Server Error' }, { status: 500 });
  }
}

import { NextRequest, NextResponse } from 'next/server';
import { AUTH_ERROR_MESSAGES, AuthErrorCode } from '@/features/auth/services/authErrors';

const BACKEND_URL = process.env.BACKEND_URL || 'http://localhost:3002';

export async function POST(request: NextRequest) {
  try {
    const registerData = await request.json();

    console.log('Sending registration data to backend:', registerData);

    const response = await fetch(`${BACKEND_URL}/v1/auth/register`, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
      },
      body: JSON.stringify(registerData),
    });

    if (!response.ok) {
      const errorData = await response.json();
      console.error('Backend registration failed:', response.status, errorData);
      let errorMessage = errorData.message || 'Registration failed';

      if (errorData.message === 'Password confirmation is required') {
        errorMessage = AUTH_ERROR_MESSAGES[AuthErrorCode.PASSWORD_CONFIRMATION_REQUIRED];
      }

      return NextResponse.json(
        { message: errorMessage, errors: errorData.errors },
        { status: response.status }
      );
    }

    const data = await response.json();
    return NextResponse.json(data, { status: 201 });
  } catch (error) {
    console.error('Registration API error:', error);
    return NextResponse.json({ message: 'Internal Server Error' }, { status: 500 });
  }
}

