import { useState, useEffect } from 'react';
import { aiAnalyticsService } from '@/features/analytics/services/aiAnalyticsService';
import { useAuthStore } from '@/features/auth/store/useAuthStore';
import type { ConsolidatedAnalytics } from '@/shared/types';

export function useAnalytics() {
  const { user } = useAuthStore();
  const [learningPatterns, setLearningPatterns] = useState<any>(null);
  const [performancePredictions, setPerformancePredictions] = useState<any>(null);
  const [studyRecommendations, setStudyRecommendations] = useState<any>(null);
  const [bktPrediction, setBKTPrediction] = useState<any>(null);
  const [burnPrediction, setBurnPrediction] = useState<any>(null);
  const [learningAnalytics, setLearningAnalytics] = useState<any>(null);
  const [isLoading, setIsLoading] = useState(true);
  const [error, setError] = useState<Error | null>(null);

  useEffect(() => {
    const loadAnalytics = async () => {
      if (!user?.id) return;

      try {
        setIsLoading(true);
        const analytics: ConsolidatedAnalytics | null =
          await aiAnalyticsService.getConsolidatedAnalytics();

        setLearningPatterns(analytics?.learningPatterns || null);
        setPerformancePredictions(analytics?.performancePredictions || null);
        setStudyRecommendations(analytics?.studyRecommendations || null);

        // Load advanced predictions in parallel
        const [bkt, burn, learning] = await Promise.all([
          aiAnalyticsService.getBKTPrediction(user.id),
          aiAnalyticsService.getBurnPrediction(user.id),
          aiAnalyticsService.getLearningAnalytics(user.id),
        ]);

        setBKTPrediction(bkt);
        setBurnPrediction(burn);
        setLearningAnalytics(learning);
      } catch (err) {
        setError(err instanceof Error ? err : new Error('Failed to load analytics'));
      } finally {
        setIsLoading(false);
      }
    };

    loadAnalytics();
  }, [user?.id]);

  const refreshAnalytics = async () => {
    if (!user?.id) return;

    try {
      setIsLoading(true);
      const analytics: ConsolidatedAnalytics | null =
        await aiAnalyticsService.getConsolidatedAnalytics();

      setLearningPatterns(analytics?.learningPatterns || null);
      setPerformancePredictions(analytics?.performancePredictions || null);
      setStudyRecommendations(analytics?.studyRecommendations || null);

      // Refresh advanced predictions in parallel
      const [bkt, burn, learning] = await Promise.all([
        aiAnalyticsService.getBKTPrediction(user.id),
        aiAnalyticsService.getBurnPrediction(user.id),
        aiAnalyticsService.getLearningAnalytics(user.id),
      ]);

      setBKTPrediction(bkt);
      setBurnPrediction(burn);
      setLearningAnalytics(learning);
    } catch (err) {
      setError(err instanceof Error ? err : new Error('Failed to refresh analytics'));
    } finally {
      setIsLoading(false);
    }
  };

  return {
    learningPatterns,
    performancePredictions,
    studyRecommendations,
    bktPrediction,
    burnPrediction,
    learningAnalytics,
    isLoading,
    error,
    refreshAnalytics,
  };
}

