'use client';

import { useState, useEffect } from 'react';
import { Card, CardContent, CardHeader, CardTitle } from '@/shared/components/ui/card';
import { Button } from '@/shared/components/ui/button';
import { Progress } from '@/shared/components/ui/progress';
import { Badge } from '@/shared/components/ui/badge';
import { Skeleton } from '@/shared/components/ui/skeleton';
import {
  Clock,
  CheckCircle,
  XCircle,
  Brain,
  Target,
  TrendingUp,
  BookOpen,
  AlertCircle,
} from 'lucide-react';
import { toast } from 'sonner';
import { useSession } from 'next-auth/react';

export interface QuizQuestion {
  id: string;
  question_text: string;
  type: 'multiple_choice' | 'multiple_select' | 'true_false';
  difficulty: 'easy' | 'medium' | 'hard';
  category: string;
  options: {
    id: string;
    option_text: string;
    is_correct: boolean;
  }[];
  explanation?: string;
  points: number;
}

interface QuizSession {
  sessionId: string;
  userId: string;
  questions: QuizQuestion[];
  currentQuestionIndex: number;
  userAbility: number;
  confidenceInterval: number;
  responses: {
    questionId: string;
    isCorrect: boolean;
    responseTime: number;
    confidence: number;
  }[];
  isComplete: boolean;
  finalScore: number;
  recommendations: string[];
}

interface AdaptiveQuizProps {
  courseId?: string;
  unitId?: string;
  onComplete?: (session: QuizSession) => void;
}

export function AdaptiveQuiz({ courseId, unitId, onComplete }: AdaptiveQuizProps) {
  const { data: sessionData } = useSession();
  const [session, setSession] = useState<QuizSession | null>(null);
  const [currentAnswer, setCurrentAnswer] = useState<any>(null);
  const [confidence, setConfidence] = useState(3);
  const [startTime, setStartTime] = useState<number>(0);
  const [loading, setLoading] = useState(false);
  const [showFeedback, setShowFeedback] = useState(false);
  const [feedback, setFeedback] = useState<any>(null);

  useEffect(() => {
    startQuiz();
  }, [courseId, unitId, sessionData]);

  const startQuiz = async () => {
    if (!sessionData?.user?.accessToken) {
      toast.error('Please log in to start a quiz.');
      setLoading(false);
      return;
    }

    try {
      setLoading(true);
      const response = await fetch('/api/assessments/adaptive-quiz/start', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          Authorization: `Bearer ${sessionData.user.accessToken}`,
        },
        body: JSON.stringify({ courseId, unitId }),
      });

      if (response.ok) {
        const quizSession = await response.json();
        setSession(quizSession);
        setStartTime(Date.now());
      } else {
        toast.error('Failed to start adaptive quiz');
      }
    } catch (error) {
      console.error('Failed to start quiz:', error);
      toast.error('Failed to start adaptive quiz');
    } finally {
      setLoading(false);
    }
  };

  const submitAnswer = async () => {
    if (!session || !currentAnswer || !sessionData?.user?.accessToken) return;

    const responseTime = Math.floor((Date.now() - startTime) / 1000);
    const currentQuestion = session.questions[session.currentQuestionIndex];

    try {
      setLoading(true);
      const response = await fetch('/api/assessments/adaptive-quiz/answer', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          Authorization: `Bearer ${sessionData.user.accessToken}`,
        },
        body: JSON.stringify({
          sessionId: session.sessionId,
          questionId: currentQuestion.id,
          answer: currentAnswer,
          responseTime,
          confidence,
        }),
      });

      if (response.ok) {
        const result = await response.json();
        setFeedback(result);
        setShowFeedback(true);
        setSession(result.session);

        if (result.isComplete) {
          onComplete?.(result.session);
        }
      } else {
        toast.error('Failed to submit answer');
      }
    } catch (error) {
      console.error('Failed to submit answer:', error);
      toast.error('Failed to submit answer');
    } finally {
      setLoading(false);
    }
  };

  const nextQuestion = () => {
    setCurrentAnswer(null);
    setConfidence(3);
    setShowFeedback(false);
    setFeedback(null);
    setStartTime(Date.now());
  };

  const getDifficultyColor = (difficulty: string) => {
    switch (difficulty) {
      case 'easy':
        return 'bg-green-100 text-green-800';
      case 'medium':
        return 'bg-yellow-100 text-yellow-800';
      case 'hard':
        return 'bg-red-100 text-red-800';
      default:
        return 'bg-gray-100 text-gray-800';
    }
  };

  const getAbilityLevel = (ability: number) => {
    if (ability < -1) return { level: 'Beginner', color: 'text-blue-600' };
    if (ability > 1) return { level: 'Advanced', color: 'text-purple-600' };
    return { level: 'Intermediate', color: 'text-green-600' };
  };

  if (loading && !session) {
    return (
      <Card>
        <CardContent className="p-8 text-center">
          <Brain className="h-12 w-12 mx-auto mb-4 text-blue-500 animate-pulse" />
          <h3 className="text-lg font-medium mb-2">Preparing Your Adaptive Quiz</h3>
          <p className="text-gray-600">Analyzing your learning profile...</p>
        </CardContent>
      </Card>
    );
  }

  if (!session) {
    return (
      <Card>
        <CardContent className="p-8 text-center">
          <AlertCircle className="h-12 w-12 mx-auto mb-4 text-red-500" />
          <h3 className="text-lg font-medium mb-2">Unable to Start Quiz</h3>
          <p className="text-gray-600 mb-4">There was an error starting your adaptive quiz.</p>
          <Button onClick={startQuiz}>Try Again</Button>
        </CardContent>
      </Card>
    );
  }

  if (session.isComplete) {
    return (
      <Card>
        <CardHeader>
          <CardTitle className="flex items-center gap-2">
            <Target className="h-6 w-6 text-green-500" />
            Quiz Complete!
          </CardTitle>
        </CardHeader>
        <CardContent className="space-y-6">
          <div className="text-center">
            <div className="text-4xl font-bold text-green-600 mb-2">
              {session.finalScore.toFixed(0)}%
            </div>
            <p className="text-gray-600">Final Score</p>
          </div>

          <div className="grid grid-cols-2 gap-4">
            <div className="text-center p-4 bg-blue-50 rounded-lg">
              <div className="text-2xl font-bold text-blue-600">{session.responses.length}</div>
              <p className="text-sm text-gray-600">Questions Answered</p>
            </div>
            <div className="text-center p-4 bg-purple-50 rounded-lg">
              <div className="text-2xl font-bold text-purple-600">
                {getAbilityLevel(session.userAbility).level}
              </div>
              <p className="text-sm text-gray-600">Estimated Level</p>
            </div>
          </div>

          {session.recommendations.length > 0 && (
            <div>
              <h4 className="font-medium mb-3 flex items-center gap-2">
                <TrendingUp className="h-4 w-4" />
                Recommendations
              </h4>
              <ul className="space-y-2">
                {session.recommendations.map((rec, index) => (
                  <li key={index} className="flex items-start gap-2">
                    <CheckCircle className="h-4 w-4 text-green-500 mt-0.5 shrink-0" />
                    <span className="text-sm text-gray-700">{rec}</span>
                  </li>
                ))}
              </ul>
            </div>
          )}

          <div className="flex gap-2">
            <Button onClick={startQuiz} className="flex-1">
              Take Another Quiz
            </Button>
            <Button variant="outline" onClick={() => onComplete?.(session)} className="flex-1">
              View Detailed Results
            </Button>
          </div>
        </CardContent>
      </Card>
    );
  }

  const currentQuestion = session.questions[session.currentQuestionIndex];
  const progress =
    ((session.currentQuestionIndex + 1) / Math.max(session.questions.length, 5)) * 100;
  const abilityInfo = getAbilityLevel(session.userAbility);

  return (
    <div className="space-y-6">
      {/* Progress Header */}
      <Card>
        <CardContent className="p-4">
          <div className="flex items-center justify-between mb-4">
            <div className="flex items-center gap-4">
              <Badge className={getDifficultyColor(currentQuestion.difficulty)}>
                {currentQuestion.difficulty}
              </Badge>
              <Badge variant="outline">{currentQuestion.category}</Badge>
              <div className="flex items-center gap-1 text-sm text-gray-600">
                <Target className="h-4 w-4" />
                <span className={abilityInfo.color}>{abilityInfo.level}</span>
              </div>
            </div>
            <div className="text-sm text-gray-600">Question {session.currentQuestionIndex + 1}</div>
          </div>
          <Progress value={progress} className="h-2" />
        </CardContent>
      </Card>

      {/* Question Card */}
      <Card>
        <CardHeader>
          <CardTitle className="text-lg leading-relaxed">{currentQuestion.question_text}</CardTitle>
        </CardHeader>
        <CardContent className="space-y-4">
          {!showFeedback ? (
            <>
              {/* Answer Options */}
              <div className="space-y-3">
                {currentQuestion.options.map(option => (
                  <label
                    key={option.id}
                    className={`flex items-center p-4 border rounded-lg cursor-pointer transition-colors ${
                      currentAnswer === option.id
                        ? 'border-blue-500 bg-blue-50'
                        : 'border-gray-200 hover:border-gray-300'
                    }`}
                  >
                    <input
                      type="radio"
                      name="answer"
                      value={option.id}
                      checked={currentAnswer === option.id}
                      onChange={e => setCurrentAnswer(e.target.value)}
                      className="sr-only"
                    />
                    <div className="flex-1">{option.option_text}</div>
                  </label>
                ))}
              </div>

              {/* Confidence Slider */}
              <div className="space-y-2">
                <label className="text-sm font-medium text-gray-700">
                  How confident are you in your answer?
                </label>
                <div className="flex items-center gap-4">
                  <span className="text-sm text-gray-500">Not sure</span>
                  <input
                    type="range"
                    min="1"
                    max="5"
                    value={confidence}
                    onChange={e => setConfidence(Number(e.target.value))}
                    className="flex-1"
                  />
                  <span className="text-sm text-gray-500">Very confident</span>
                </div>
                <div className="text-center">
                  <Badge variant="outline">{confidence}/5</Badge>
                </div>
              </div>

              <Button
                onClick={submitAnswer}
                disabled={!currentAnswer || loading}
                className="w-full"
              >
                {loading ? 'Submitting...' : 'Submit Answer'}
              </Button>
            </>
          ) : (
            /* Feedback Display */
            <div className="space-y-4">
              <div
                className={`flex items-center gap-2 p-4 rounded-lg ${
                  feedback.isCorrect ? 'bg-green-50 text-green-800' : 'bg-red-50 text-red-800'
                }`}
              >
                {feedback.isCorrect ? (
                  <CheckCircle className="h-5 w-5" />
                ) : (
                  <XCircle className="h-5 w-5" />
                )}
                <span className="font-medium">{feedback.isCorrect ? 'Correct!' : 'Incorrect'}</span>
              </div>

              {feedback.explanation && (
                <div className="p-4 bg-blue-50 rounded-lg">
                  <h4 className="font-medium text-blue-900 mb-2">Explanation</h4>
                  <p className="text-blue-800 text-sm">{feedback.explanation}</p>
                </div>
              )}

              <Button onClick={nextQuestion} className="w-full" disabled={session.isComplete}>
                {session.isComplete ? 'Quiz Complete' : 'Next Question'}
              </Button>
            </div>
          )}
        </CardContent>
      </Card>
    </div>
  );
}

'use client';

import { useState, useEffect } from 'react';
import { Card, CardContent, CardHeader, CardTitle } from '@/shared/components/ui/card';
import { Button } from '@/shared/components/ui/button';
import { Badge } from '@/shared/components/ui/badge';
import { Input } from '@/shared/components/ui/input';
import { Textarea } from '@/shared/components/ui/textarea';
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from '@/shared/components/ui/select';
import {
  Plus,
  Search,
  Filter,
  Edit,
  Trash2,
  Copy,
  Eye,
  Users,
  Clock,
  Target,
  BookOpen,
  Settings,
  BarChart3,
  Download,
  Upload,
  FileText,
  Stethoscope,
  Activity,
  Heart,
} from 'lucide-react';
import { toast } from 'sonner';

interface ClinicalCase {
  id: string;
  title: string;
  description: string;
  complexity: 'simple' | 'moderate' | 'complex' | 'expert';
  specialty: string;
  status: 'draft' | 'published' | 'archived';
  estimated_duration_minutes: number;
  learning_objectives: string[];
  tags: string[];
  created_at: Date;
  updated_at: Date;
  created_by: string;
  creator_name: string;
  attempts_count: number;
  average_score: number;
  average_completion_time: number;
}

interface CaseFilters {
  search: string;
  specialty: string;
  complexity: string;
  status: string;
  created_by: string;
}

interface CaseLibraryManagementProps {
  userRole: 'teacher' | 'admin';
  courseId?: string;
  unitId?: string;
}

export function CaseLibraryManagement({ userRole, courseId, unitId }: CaseLibraryManagementProps) {
  const [cases, setCases] = useState<ClinicalCase[]>([]);
  const [filteredCases, setFilteredCases] = useState<ClinicalCase[]>([]);
  const [loading, setLoading] = useState(true);
  const [showCreateModal, setShowCreateModal] = useState(false);
  const [selectedCase, setSelectedCase] = useState<ClinicalCase | null>(null);
  const [filters, setFilters] = useState<CaseFilters>({
    search: '',
    specialty: '',
    complexity: '',
    status: '',
    created_by: '',
  });

  const specialties = [
    'Internal Medicine',
    'Cardiology',
    'Neurology',
    'Pediatrics',
    'Surgery',
    'Emergency',
    'Psychiatry',
    'Obstetrics',
    'Dermatology',
    'Radiology',
  ];

  const complexities = ['simple', 'moderate', 'complex', 'expert'];
  const statuses = ['draft', 'published', 'archived'];

  useEffect(() => {
    loadCases();
  }, [courseId, unitId]);

  useEffect(() => {
    applyFilters();
  }, [cases, filters]);

  const loadCases = async () => {
    try {
      setLoading(true);
      const params = new URLSearchParams();
      if (courseId) params.append('course_id', courseId);
      if (unitId) params.append('unit_id', unitId);

      const response = await fetch(`/api/clinical-cases?${params}`, {
        headers: {
          Authorization: `Bearer ${localStorage.getItem('token')}`,
        },
      });

      if (response.ok) {
        const casesData = await response.json();
        setCases(casesData);
      } else {
        toast.error('Failed to load clinical cases');
      }
    } catch (error) {
      console.error('Failed to load cases:', error);
      toast.error('Failed to load clinical cases');
    } finally {
      setLoading(false);
    }
  };

  const applyFilters = () => {
    let filtered = [...cases];

    if (filters.search) {
      const searchLower = filters.search.toLowerCase();
      filtered = filtered.filter(
        case_ =>
          case_.title.toLowerCase().includes(searchLower) ||
          case_.description.toLowerCase().includes(searchLower) ||
          case_.tags.some(tag => tag.toLowerCase().includes(searchLower))
      );
    }

    if (filters.specialty) {
      filtered = filtered.filter(case_ => case_.specialty === filters.specialty);
    }

    if (filters.complexity) {
      filtered = filtered.filter(case_ => case_.complexity === filters.complexity);
    }

    if (filters.status) {
      filtered = filtered.filter(case_ => case_.status === filters.status);
    }

    if (filters.created_by) {
      filtered = filtered.filter(case_ => case_.created_by === filters.created_by);
    }

    setFilteredCases(filtered);
  };

  const handleFilterChange = (key: keyof CaseFilters, value: string) => {
    setFilters(prev => ({ ...prev, [key]: value }));
  };

  const clearFilters = () => {
    setFilters({
      search: '',
      specialty: '',
      complexity: '',
      status: '',
      created_by: '',
    });
  };

  const duplicateCase = async (caseId: string) => {
    try {
      const response = await fetch(`/api/clinical-cases/${caseId}/duplicate`, {
        method: 'POST',
        headers: {
          Authorization: `Bearer ${localStorage.getItem('token')}`,
        },
      });

      if (response.ok) {
        toast.success('Case duplicated successfully');
        loadCases();
      } else {
        toast.error('Failed to duplicate case');
      }
    } catch (error) {
      console.error('Failed to duplicate case:', error);
      toast.error('Failed to duplicate case');
    }
  };

  const deleteCase = async (caseId: string) => {
    if (!confirm('Are you sure you want to delete this case? This action cannot be undone.')) {
      return;
    }

    try {
      const response = await fetch(`/api/clinical-cases/${caseId}`, {
        method: 'DELETE',
        headers: {
          Authorization: `Bearer ${localStorage.getItem('token')}`,
        },
      });

      if (response.ok) {
        toast.success('Case deleted successfully');
        loadCases();
      } else {
        toast.error('Failed to delete case');
      }
    } catch (error) {
      console.error('Failed to delete case:', error);
      toast.error('Failed to delete case');
    }
  };

  const updateCaseStatus = async (caseId: string, newStatus: string) => {
    try {
      const response = await fetch(`/api/clinical-cases/${caseId}`, {
        method: 'PATCH',
        headers: {
          'Content-Type': 'application/json',
          Authorization: `Bearer ${localStorage.getItem('token')}`,
        },
        body: JSON.stringify({ status: newStatus }),
      });

      if (response.ok) {
        toast.success(`Case ${newStatus} successfully`);
        loadCases();
      } else {
        toast.error(`Failed to ${newStatus} case`);
      }
    } catch (error) {
      console.error(`Failed to ${newStatus} case:`, error);
      toast.error(`Failed to ${newStatus} case`);
    }
  };

  const getComplexityColor = (complexity: string) => {
    switch (complexity) {
      case 'simple':
        return 'bg-green-100 text-green-800';
      case 'moderate':
        return 'bg-yellow-100 text-yellow-800';
      case 'complex':
        return 'bg-orange-100 text-orange-800';
      case 'expert':
        return 'bg-red-100 text-red-800';
      default:
        return 'bg-gray-100 text-gray-800';
    }
  };

  const getStatusColor = (status: string) => {
    switch (status) {
      case 'published':
        return 'bg-green-100 text-green-800';
      case 'draft':
        return 'bg-yellow-100 text-yellow-800';
      case 'archived':
        return 'bg-gray-100 text-gray-800';
      default:
        return 'bg-gray-100 text-gray-800';
    }
  };

  const getSectionIcon = (type: string) => {
    switch (type) {
      case 'history':
        return <FileText className="h-4 w-4" />;
      case 'physical_exam':
        return <Stethoscope className="h-4 w-4" />;
      case 'diagnostics':
        return <Activity className="h-4 w-4" />;
      case 'treatment':
        return <Heart className="h-4 w-4" />;
      default:
        return <BookOpen className="h-4 w-4" />;
    }
  };

  if (loading) {
    return (
      <div className="space-y-4">
        {[...Array(5)].map((_, i) => (
          <Card key={i}>
            <CardContent className="p-6">
              <div className="animate-pulse space-y-3">
                <div className="h-4 bg-gray-200 rounded w-3/4"></div>
                <div className="h-3 bg-gray-200 rounded w-1/2"></div>
                <div className="flex gap-2">
                  <div className="h-6 bg-gray-200 rounded w-16"></div>
                  <div className="h-6 bg-gray-200 rounded w-20"></div>
                </div>
              </div>
            </CardContent>
          </Card>
        ))}
      </div>
    );
  }

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="flex items-center justify-between">
        <div>
          <h2 className="text-2xl font-bold text-gray-900">Clinical Case Library</h2>
          <p className="text-gray-600">Manage and organize your clinical case studies</p>
        </div>
        <div className="flex items-center gap-2">
          <Button variant="outline" size="sm">
            <Download className="h-4 w-4 mr-2" />
            Export
          </Button>
          <Button variant="outline" size="sm">
            <Upload className="h-4 w-4 mr-2" />
            Import
          </Button>
          <Button onClick={() => setShowCreateModal(true)}>
            <Plus className="h-4 w-4 mr-2" />
            Create Case
          </Button>
        </div>
      </div>

      {/* Filters */}
      <Card>
        <CardHeader>
          <CardTitle className="flex items-center gap-2">
            <Filter className="h-5 w-5" />
            Filters
          </CardTitle>
        </CardHeader>
        <CardContent>
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-5 gap-4">
            <div className="relative">
              <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 h-4 w-4 text-gray-400" />
              <Input
                placeholder="Search cases..."
                value={filters.search}
                onChange={e => handleFilterChange('search', e.target.value)}
                className="pl-10"
              />
            </div>

            <Select
              value={filters.specialty}
              onValueChange={value => handleFilterChange('specialty', value)}
            >
              <SelectTrigger>
                <SelectValue placeholder="All Specialties" />
              </SelectTrigger>
              <SelectContent>
                <SelectItem value="">All Specialties</SelectItem>
                {specialties.map(specialty => (
                  <SelectItem key={specialty} value={specialty}>
                    {specialty}
                  </SelectItem>
                ))}
              </SelectContent>
            </Select>

            <Select
              value={filters.complexity}
              onValueChange={value => handleFilterChange('complexity', value)}
            >
              <SelectTrigger>
                <SelectValue placeholder="All Complexities" />
              </SelectTrigger>
              <SelectContent>
                <SelectItem value="">All Complexities</SelectItem>
                {complexities.map(complexity => (
                  <SelectItem key={complexity} value={complexity}>
                    {complexity.charAt(0).toUpperCase() + complexity.slice(1)}
                  </SelectItem>
                ))}
              </SelectContent>
            </Select>

            <Select
              value={filters.status}
              onValueChange={value => handleFilterChange('status', value)}
            >
              <SelectTrigger>
                <SelectValue placeholder="All Statuses" />
              </SelectTrigger>
              <SelectContent>
                <SelectItem value="">All Statuses</SelectItem>
                {statuses.map(status => (
                  <SelectItem key={status} value={status}>
                    {status.charAt(0).toUpperCase() + status.slice(1)}
                  </SelectItem>
                ))}
              </SelectContent>
            </Select>

            <Button variant="outline" onClick={clearFilters}>
              Clear Filters
            </Button>
          </div>
        </CardContent>
      </Card>

      {/* Cases Grid */}
      <div className="grid grid-cols-1 lg:grid-cols-2 xl:grid-cols-3 gap-6">
        {filteredCases.map(case_ => (
          <Card key={case_.id} className="hover:shadow-lg transition-shadow">
            <CardHeader>
              <div className="flex items-start justify-between">
                <div className="flex-1">
                  <CardTitle className="text-lg line-clamp-2 mb-2">{case_.title}</CardTitle>
                  <div className="flex items-center gap-2 mb-2">
                    <Badge className={getComplexityColor(case_.complexity)}>
                      {case_.complexity}
                    </Badge>
                    <Badge className={getStatusColor(case_.status)}>{case_.status}</Badge>
                    <Badge variant="outline">{case_.specialty}</Badge>
                  </div>
                </div>
                <div className="flex items-center gap-1">
                  <Button variant="ghost" size="sm" onClick={() => setSelectedCase(case_)}>
                    <Eye className="h-4 w-4" />
                  </Button>
                  <Button variant="ghost" size="sm">
                    <Edit className="h-4 w-4" />
                  </Button>
                  <Button variant="ghost" size="sm" onClick={() => duplicateCase(case_.id)}>
                    <Copy className="h-4 w-4" />
                  </Button>
                  <Button variant="ghost" size="sm" onClick={() => deleteCase(case_.id)}>
                    <Trash2 className="h-4 w-4 text-red-500" />
                  </Button>
                </div>
              </div>
            </CardHeader>
            <CardContent>
              <p className="text-sm text-gray-600 mb-4 line-clamp-3">{case_.description}</p>

              <div className="space-y-3">
                <div className="flex items-center justify-between text-sm">
                  <div className="flex items-center gap-1">
                    <Clock className="h-4 w-4 text-gray-400" />
                    <span>{case_.estimated_duration_minutes} min</span>
                  </div>
                  <div className="flex items-center gap-1">
                    <Users className="h-4 w-4 text-gray-400" />
                    <span>{case_.attempts_count} attempts</span>
                  </div>
                </div>

                {case_.attempts_count > 0 && (
                  <div className="flex items-center justify-between text-sm">
                    <div className="flex items-center gap-1">
                      <Target className="h-4 w-4 text-gray-400" />
                      <span>Avg Score: {case_.average_score.toFixed(1)}%</span>
                    </div>
                    <div className="flex items-center gap-1">
                      <BarChart3 className="h-4 w-4 text-gray-400" />
                      <span>Avg Time: {Math.round(case_.average_completion_time / 60)}m</span>
                    </div>
                  </div>
                )}

                <div className="flex flex-wrap gap-1">
                  {case_.tags.slice(0, 3).map((tag, index) => (
                    <Badge key={index} variant="outline" className="text-xs">
                      {tag}
                    </Badge>
                  ))}
                  {case_.tags.length > 3 && (
                    <Badge variant="outline" className="text-xs">
                      +{case_.tags.length - 3} more
                    </Badge>
                  )}
                </div>

                <div className="flex items-center justify-between pt-2 border-t">
                  <span className="text-xs text-gray-500">By {case_.creator_name}</span>
                  <span className="text-xs text-gray-500">
                    {new Date(case_.updated_at).toLocaleDateString()}
                  </span>
                </div>

                {case_.status === 'draft' && (
                  <Button
                    size="sm"
                    className="w-full"
                    onClick={() => updateCaseStatus(case_.id, 'published')}
                  >
                    Publish Case
                  </Button>
                )}
              </div>
            </CardContent>
          </Card>
        ))}
      </div>

      {filteredCases.length === 0 && (
        <Card>
          <CardContent className="p-8 text-center">
            <BookOpen className="h-12 w-12 mx-auto mb-4 text-gray-400" />
            <h3 className="text-lg font-medium mb-2">No Cases Found</h3>
            <p className="text-gray-600 mb-4">
              {cases.length === 0
                ? 'Create your first clinical case to get started.'
                : 'Try adjusting your filters to find more cases.'}
            </p>
            {cases.length === 0 && (
              <Button onClick={() => setShowCreateModal(true)}>
                <Plus className="h-4 w-4 mr-2" />
                Create Your First Case
              </Button>
            )}
          </CardContent>
        </Card>
      )}
    </div>
  );
}

'use client';

import { useState, useEffect } from 'react';
import { Card, CardContent, CardHeader, CardTitle } from '@/shared/components/ui/card';
import { Badge } from '@/shared/components/ui/badge';
import { Progress } from '@/shared/components/ui/progress';
import { Button } from '@/shared/components/ui/button';
import {
  Clock,
  CheckCircle,
  Circle,
  Target,
  TrendingUp,
  Award,
  Brain,
  Stethoscope,
  FileText,
  Activity,
  Heart,
  BarChart3,
  Calendar,
  User,
  BookOpen,
} from 'lucide-react';
import {
  LineChart,
  Line,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip,
  ResponsiveContainer,
  RadarChart,
  PolarGrid,
  PolarAngleAxis,
  PolarRadiusAxis,
  Radar,
} from 'recharts';

interface CaseProgress {
  case_id: string;
  case_title: string;
  attempt_id: string;
  status: 'in_progress' | 'completed' | 'abandoned';
  started_at: Date;
  completed_at?: Date;
  total_time_spent: number;
  current_section: string;
  completed_sections: string[];
  total_sections: number;
  score: number;
  max_score: number;
  percentage: number;
  decisions_made: {
    decision_point_id: string;
    selected_option_id: string;
    timestamp: Date;
    points_earned: number;
    is_optimal: boolean;
  }[];
  section_performance: {
    section_id: string;
    section_title: string;
    section_type: string;
    time_spent: number;
    points_earned: number;
    max_points: number;
    completion_percentage: number;
  }[];
  learning_objectives_progress: {
    objective: string;
    progress: number;
    evidence: string[];
  }[];
  clinical_skills_assessment: {
    history_taking: number;
    physical_examination: number;
    diagnostic_reasoning: number;
    treatment_planning: number;
    communication: number;
    professionalism: number;
  };
}

interface CaseProgressTrackerProps {
  userId: string;
  caseId?: string;
  attemptId?: string;
  showDetailedAnalytics?: boolean;
}

export function CaseProgressTracker({
  userId,
  caseId,
  attemptId,
  showDetailedAnalytics = false,
}: CaseProgressTrackerProps) {
  const [progress, setProgress] = useState<CaseProgress[]>([]);
  const [selectedProgress, setSelectedProgress] = useState<CaseProgress | null>(null);
  const [loading, setLoading] = useState(true);
  const [timeframe, setTimeframe] = useState<'week' | 'month' | 'all'>('month');

  useEffect(() => {
    loadProgress();
  }, [userId, caseId, attemptId, timeframe]);

  const loadProgress = async () => {
    try {
      setLoading(true);
      const params = new URLSearchParams();
      if (caseId) params.append('caseId', caseId);
      if (attemptId) params.append('attemptId', attemptId);
      params.append('timeframe', timeframe);

      const response = await fetch(`/api/clinical-cases/progress?${params}`, {
        headers: {
          Authorization: `Bearer ${localStorage.getItem('token')}`,
        },
      });

      if (response.ok) {
        const progressData = await response.json();
        setProgress(Array.isArray(progressData) ? progressData : [progressData]);
        if (progressData.length > 0) {
          setSelectedProgress(progressData[0]);
        }
      }
    } catch (error) {
      console.error('Failed to load progress:', error);
    } finally {
      setLoading(false);
    }
  };

  const formatTime = (seconds: number): string => {
    const hours = Math.floor(seconds / 3600);
    const minutes = Math.floor((seconds % 3600) / 60);

    if (hours > 0) {
      return `${hours}h ${minutes}m`;
    }
    return `${minutes}m`;
  };

  const getStatusColor = (status: string) => {
    switch (status) {
      case 'completed':
        return 'bg-green-100 text-green-800';
      case 'inProgress':
        return 'bg-blue-100 text-blue-800';
      case 'abandoned':
        return 'bg-red-100 text-red-800';
      default:
        return 'bg-gray-100 text-gray-800';
    }
  };

  const getSectionIcon = (type: string) => {
    switch (type) {
      case 'history':
        return <FileText className="h-4 w-4" />;
      case 'physical_exam':
        return <Stethoscope className="h-4 w-4" />;
      case 'diagnostics':
        return <Activity className="h-4 w-4" />;
      case 'treatment':
        return <Heart className="h-4 w-4" />;
      case 'follow_up':
        return <Clock className="h-4 w-4" />;
      default:
        return <Circle className="h-4 w-4" />;
    }
  };

  const calculateOverallProgress = (progressItem: CaseProgress): number => {
    return (progressItem.completed_sections.length / progressItem.total_sections) * 100;
  };

  const getPerformanceColor = (percentage: number): string => {
    if (percentage >= 80) return 'text-green-600';
    if (percentage >= 60) return 'text-yellow-600';
    return 'text-red-600';
  };

  if (loading) {
    return (
      <div className="space-y-4">
        {[...Array(3)].map((_, i) => (
          <Card key={i}>
            <CardContent className="p-6">
              <div className="animate-pulse space-y-3">
                <div className="h-4 bg-gray-200 rounded w-3/4"></div>
                <div className="h-3 bg-gray-200 rounded w-1/2"></div>
                <div className="h-2 bg-gray-200 rounded"></div>
              </div>
            </CardContent>
          </Card>
        ))}
      </div>
    );
  }

  if (progress.length === 0) {
    return (
      <Card>
        <CardContent className="p-8 text-center">
          <BarChart3 className="h-12 w-12 mx-auto mb-4 text-gray-400" />
          <h3 className="text-lg font-medium mb-2">No Progress Data</h3>
          <p className="text-gray-600">
            Start working on clinical cases to see your progress here.
          </p>
        </CardContent>
      </Card>
    );
  }

  return (
    <div className="space-y-6">
      {/* Timeframe Selector */}
      <div className="flex items-center gap-2">
        <span className="text-sm font-medium text-gray-700">Timeframe:</span>
        {(['week', 'month', 'all'] as const).map(period => (
          <Button
            key={period}
            variant={timeframe === period ? 'default' : 'outline'}
            size="sm"
            onClick={() => setTimeframe(period)}
          >
            {period === 'all' ? 'All Time' : `Past ${period}`}
          </Button>
        ))}
      </div>

      {/* Progress Overview */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
        <Card>
          <CardContent className="p-4">
            <div className="flex items-center gap-2 mb-2">
              <BookOpen className="h-4 w-4 text-blue-500" />
              <span className="text-sm font-medium text-gray-700">Cases Started</span>
            </div>
            <div className="text-2xl font-bold text-blue-600">{progress.length}</div>
          </CardContent>
        </Card>

        <Card>
          <CardContent className="p-4">
            <div className="flex items-center gap-2 mb-2">
              <CheckCircle className="h-4 w-4 text-green-500" />
              <span className="text-sm font-medium text-gray-700">Completed</span>
            </div>
            <div className="text-2xl font-bold text-green-600">
              {progress.filter(p => p.status === 'completed').length}
            </div>
          </CardContent>
        </Card>

        <Card>
          <CardContent className="p-4">
            <div className="flex items-center gap-2 mb-2">
              <Target className="h-4 w-4 text-purple-500" />
              <span className="text-sm font-medium text-gray-700">Avg Score</span>
            </div>
            <div className="text-2xl font-bold text-purple-600">
              {progress.length > 0
                ? Math.round(progress.reduce((sum, p) => sum + p.percentage, 0) / progress.length)
                : 0}
              %
            </div>
          </CardContent>
        </Card>

        <Card>
          <CardContent className="p-4">
            <div className="flex items-center gap-2 mb-2">
              <Clock className="h-4 w-4 text-orange-500" />
              <span className="text-sm font-medium text-gray-700">Total Time</span>
            </div>
            <div className="text-2xl font-bold text-orange-600">
              {formatTime(progress.reduce((sum, p) => sum + p.total_time_spent, 0))}
            </div>
          </CardContent>
        </Card>
      </div>

      {/* Individual Case Progress */}
      <div className="space-y-4">
        {progress.map(progressItem => (
          <Card
            key={progressItem.attempt_id}
            className="cursor-pointer hover:shadow-md transition-shadow"
            onClick={() => setSelectedProgress(progressItem)}
          >
            <CardHeader>
              <div className="flex items-start justify-between">
                <div>
                  <CardTitle className="text-lg">{progressItem.case_title}</CardTitle>
                  <div className="flex items-center gap-2 mt-2">
                    <Badge className={getStatusColor(progressItem.status)}>
                      {progressItem.status.replace('_', ' ')}
                    </Badge>
                    <span className="text-sm text-gray-600">
                      Started {new Date(progressItem.started_at).toLocaleDateString()}
                    </span>
                    {progressItem.completed_at && (
                      <span className="text-sm text-gray-600">
                        ΓÇó Completed {new Date(progressItem.completed_at).toLocaleDateString()}
                      </span>
                    )}
                  </div>
                </div>
                <div className="text-right">
                  <div
                    className={`text-2xl font-bold ${getPerformanceColor(progressItem.percentage)}`}
                  >
                    {progressItem.percentage.toFixed(0)}%
                  </div>
                  <p className="text-sm text-gray-600">Score</p>
                </div>
              </div>
            </CardHeader>
            <CardContent>
              <div className="space-y-4">
                <div>
                  <div className="flex items-center justify-between mb-2">
                    <span className="text-sm font-medium text-gray-700">Overall Progress</span>
                    <span className="text-sm text-gray-600">
                      {progressItem.completed_sections.length}/{progressItem.total_sections}{' '}
                      sections
                    </span>
                  </div>
                  <Progress value={calculateOverallProgress(progressItem)} className="h-2" />
                </div>

                <div className="grid grid-cols-2 md:grid-cols-4 gap-4 text-sm">
                  <div>
                    <span className="text-gray-600">Time Spent</span>
                    <div className="font-medium">{formatTime(progressItem.total_time_spent)}</div>
                  </div>
                  <div>
                    <span className="text-gray-600">Decisions Made</span>
                    <div className="font-medium">{progressItem.decisions_made.length}</div>
                  </div>
                  <div>
                    <span className="text-gray-600">Optimal Decisions</span>
                    <div className="font-medium">
                      {progressItem.decisions_made.filter(d => d.is_optimal).length}
                    </div>
                  </div>
                  <div>
                    <span className="text-gray-600">Points Earned</span>
                    <div className="font-medium">
                      {progressItem.score}/{progressItem.max_score}
                    </div>
                  </div>
                </div>
              </div>
            </CardContent>
          </Card>
        ))}
      </div>

      {/* Detailed Analytics */}
      {showDetailedAnalytics && selectedProgress && (
        <Card>
          <CardHeader>
            <CardTitle className="flex items-center gap-2">
              <BarChart3 className="h-5 w-5 text-blue-500" />
              Detailed Analytics - {selectedProgress.case_title}
            </CardTitle>
          </CardHeader>
          <CardContent className="space-y-6">
            {/* Section Performance */}
            <div>
              <h4 className="font-medium text-gray-900 mb-4">Section Performance</h4>
              <div className="space-y-3">
                {selectedProgress.section_performance.map(section => (
                  <div
                    key={section.section_id}
                    className="flex items-center gap-4 p-3 border rounded-lg"
                  >
                    <div className="flex items-center gap-2 flex-1">
                      {getSectionIcon(section.section_type)}
                      <span className="font-medium">{section.section_title}</span>
                    </div>
                    <div className="text-sm text-gray-600">{formatTime(section.time_spent)}</div>
                    <div className="text-sm font-medium">
                      {section.points_earned}/{section.max_points} pts
                    </div>
                    <div className="w-24">
                      <Progress value={section.completion_percentage} className="h-2" />
                    </div>
                  </div>
                ))}
              </div>
            </div>

            {/* Learning Objectives Progress */}
            <div>
              <h4 className="font-medium text-gray-900 mb-4">Learning Objectives</h4>
              <div className="space-y-3">
                {selectedProgress.learning_objectives_progress.map((objective, index) => (
                  <div key={index} className="p-3 border rounded-lg">
                    <div className="flex items-center justify-between mb-2">
                      <span className="font-medium text-sm">{objective.objective}</span>
                      <Badge variant={objective.progress >= 80 ? 'default' : 'outline'}>
                        {objective.progress}%
                      </Badge>
                    </div>
                    <Progress value={objective.progress} className="h-2 mb-2" />
                    {objective.evidence.length > 0 && (
                      <div className="text-xs text-gray-600">
                        <span className="font-medium">Evidence: </span>
                        {objective.evidence.join(', ')}
                      </div>
                    )}
                  </div>
                ))}
              </div>
            </div>

            {/* Clinical Skills Radar Chart */}
            <div>
              <h4 className="font-medium text-gray-900 mb-4">Clinical Skills Assessment</h4>
              <div className="h-64">
                <ResponsiveContainer width="100%" height="100%">
                  <RadarChart
                    data={[
                      {
                        skill: 'History Taking',
                        score: selectedProgress.clinical_skills_assessment.history_taking,
                      },
                      {
                        skill: 'Physical Exam',
                        score: selectedProgress.clinical_skills_assessment.physical_examination,
                      },
                      {
                        skill: 'Diagnostic Reasoning',
                        score: selectedProgress.clinical_skills_assessment.diagnostic_reasoning,
                      },
                      {
                        skill: 'Treatment Planning',
                        score: selectedProgress.clinical_skills_assessment.treatment_planning,
                      },
                      {
                        skill: 'Communication',
                        score: selectedProgress.clinical_skills_assessment.communication,
                      },
                      {
                        skill: 'Professionalism',
                        score: selectedProgress.clinical_skills_assessment.professionalism,
                      },
                    ]}
                  >
                    <PolarGrid />
                    <PolarAngleAxis dataKey="skill" />
                    <PolarRadiusAxis angle={90} domain={[0, 100]} />
                    <Radar
                      name="Clinical Skills"
                      dataKey="score"
                      stroke="#3B82F6"
                      fill="#3B82F6"
                      fillOpacity={0.3}
                    />
                  </RadarChart>
                </ResponsiveContainer>
              </div>
            </div>
          </CardContent>
        </Card>
      )}
    </div>
  );
}

'use client';

import { useState, useEffect } from 'react';
import { Card, CardContent, CardHeader, CardTitle } from '@/shared/components/ui/card';
import { Button } from '@/shared/components/ui/button';
import { Badge } from '@/shared/components/ui/badge';
import {
  GitBranch,
  ArrowRight,
  ArrowDown,
  CheckCircle,
  XCircle,
  AlertTriangle,
  Lightbulb,
  Target,
  Clock,
  Award,
} from 'lucide-react';

interface DecisionNode {
  id: string;
  type: 'decision' | 'outcome' | 'consequence';
  title: string;
  content: string;
  options?: {
    id: string;
    text: string;
    leads_to: string;
    is_optimal: boolean;
    points: number;
    immediate_feedback?: string;
    consequences?: string[];
  }[];
  outcomes?: {
    type: 'success' | 'warning' | 'error';
    message: string;
    learning_points: string[];
    next_actions?: string[];
  }[];
  position: { x: number; y: number };
  unlocked: boolean;
  visited: boolean;
}

interface DecisionPath {
  nodes: string[];
  decisions: {
    node_id: string;
    option_id: string;
    timestamp: Date;
    points_earned: number;
  }[];
  total_points: number;
  efficiency_score: number;
  clinical_reasoning_score: number;
}

interface DecisionTreeLogicProps {
  caseId: string;
  attemptId: string;
  decisionTree: {
    nodes: DecisionNode[];
    starting_node: string;
    optimal_paths: string[][];
    learning_objectives: string[];
  };
  onPathComplete?: (path: DecisionPath) => void;
  onDecisionMade?: (nodeId: string, optionId: string) => void;
}

export function DecisionTreeLogic({
  caseId,
  attemptId,
  decisionTree,
  onPathComplete,
  onDecisionMade,
}: DecisionTreeLogicProps) {
  const [currentNode, setCurrentNode] = useState<string>(decisionTree.starting_node);
  const [visitedNodes, setVisitedNodes] = useState<Set<string>>(
    new Set([decisionTree.starting_node])
  );
  const [decisionPath, setDecisionPath] = useState<DecisionPath>({
    nodes: [decisionTree.starting_node],
    decisions: [],
    total_points: 0,
    efficiency_score: 100,
    clinical_reasoning_score: 0,
  });
  const [showConsequences, setShowConsequences] = useState<Record<string, boolean>>({});
  const [selectedOptions, setSelectedOptions] = useState<Record<string, string>>({});

  const currentNodeData = decisionTree.nodes.find(node => node.id === currentNode);

  const makeDecision = async (optionId: string) => {
    if (!currentNodeData) return;

    const selectedOption = currentNodeData.options?.find(opt => opt.id === optionId);
    if (!selectedOption) return;

    // Record the decision
    const decision = {
      node_id: currentNode,
      option_id: optionId,
      timestamp: new Date(),
      points_earned: selectedOption.points,
    };

    // Update decision path
    const newPath = {
      ...decisionPath,
      decisions: [...decisionPath.decisions, decision],
      total_points: decisionPath.total_points + selectedOption.points,
      nodes: [...decisionPath.nodes, selectedOption.leads_to],
    };

    // Calculate efficiency score (decreases with suboptimal choices)
    if (!selectedOption.is_optimal) {
      newPath.efficiency_score = Math.max(0, newPath.efficiency_score - 10);
    }

    // Calculate clinical reasoning score
    newPath.clinical_reasoning_score = calculateClinicalReasoningScore(newPath);

    setDecisionPath(newPath);
    setSelectedOptions(prev => ({ ...prev, [currentNode]: optionId }));

    // Show immediate feedback if available
    if (selectedOption.immediate_feedback) {
      setShowConsequences(prev => ({ ...prev, [currentNode]: true }));
    }

    // Move to next node after a brief delay
    setTimeout(
      () => {
        setCurrentNode(selectedOption.leads_to);
        setVisitedNodes(prev => new Set([...prev, selectedOption.leads_to]));

        // Check if path is complete
        const nextNode = decisionTree.nodes.find(node => node.id === selectedOption.leads_to);
        if (nextNode?.type === 'outcome') {
          onPathComplete?.(newPath);
        }
      },
      selectedOption.immediate_feedback ? 2000 : 500
    );

    // Notify parent component
    onDecisionMade?.(currentNode, optionId);

    // Save decision to backend
    await saveDecision(decision);
  };

  const saveDecision = async (decision: any) => {
    try {
      await fetch(`/api/clinical-cases/attempts/${attemptId}/decisions`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          Authorization: `Bearer ${localStorage.getItem('token')}`,
        },
        body: JSON.stringify(decision),
      });
    } catch (error) {
      console.error('Failed to save decision:', error);
    }
  };

  const calculateClinicalReasoningScore = (path: DecisionPath): number => {
    const totalDecisions = path.decisions.length;
    if (totalDecisions === 0) return 0;

    const optimalDecisions = path.decisions.filter(decision => {
      const node = decisionTree.nodes.find(n => n.id === decision.node_id);
      const option = node?.options?.find(opt => opt.id === decision.option_id);
      return option?.is_optimal;
    }).length;

    return Math.round((optimalDecisions / totalDecisions) * 100);
  };

  const getNodeTypeIcon = (type: string) => {
    switch (type) {
      case 'decision':
        return <GitBranch className="h-5 w-5 text-blue-500" />;
      case 'outcome':
        return <Target className="h-5 w-5 text-green-500" />;
      case 'consequence':
        return <AlertTriangle className="h-5 w-5 text-yellow-500" />;
      default:
        return <GitBranch className="h-5 w-5 text-gray-500" />;
    }
  };

  const getOutcomeColor = (type: string) => {
    switch (type) {
      case 'success':
        return 'border-green-500 bg-green-50';
      case 'warning':
        return 'border-yellow-500 bg-yellow-50';
      case 'error':
        return 'border-red-500 bg-red-50';
      default:
        return 'border-gray-500 bg-gray-50';
    }
  };

  const isOptimalPath = () => {
    return decisionTree.optimal_paths.some(optimalPath =>
      optimalPath.every(nodeId => decisionPath.nodes.includes(nodeId))
    );
  };

  if (!currentNodeData) {
    return (
      <Card>
        <CardContent className="p-8 text-center">
          <AlertTriangle className="h-12 w-12 mx-auto mb-4 text-red-500" />
          <h3 className="text-lg font-medium mb-2">Decision Tree Error</h3>
          <p className="text-gray-600">Unable to load the current decision point.</p>
        </CardContent>
      </Card>
    );
  }

  return (
    <div className="space-y-6">
      {/* Progress Header */}
      <Card>
        <CardHeader>
          <div className="flex items-center justify-between">
            <CardTitle className="flex items-center gap-2">
              <GitBranch className="h-6 w-6 text-blue-500" />
              Clinical Decision Tree
            </CardTitle>
            <div className="flex items-center gap-4">
              <div className="text-center">
                <div className="text-lg font-bold text-blue-600">{decisionPath.total_points}</div>
                <p className="text-xs text-gray-600">Points</p>
              </div>
              <div className="text-center">
                <div className="text-lg font-bold text-green-600">
                  {decisionPath.efficiency_score}%
                </div>
                <p className="text-xs text-gray-600">Efficiency</p>
              </div>
              <div className="text-center">
                <div className="text-lg font-bold text-purple-600">
                  {decisionPath.clinical_reasoning_score}%
                </div>
                <p className="text-xs text-gray-600">Reasoning</p>
              </div>
            </div>
          </div>
        </CardHeader>
      </Card>

      {/* Current Decision Node */}
      <Card className="border-l-4 border-l-blue-500">
        <CardHeader>
          <CardTitle className="flex items-center gap-2">
            {getNodeTypeIcon(currentNodeData.type)}
            {currentNodeData.title}
          </CardTitle>
        </CardHeader>
        <CardContent className="space-y-4">
          <div className="prose max-w-none">
            <p>{currentNodeData.content}</p>
          </div>

          {/* Decision Options */}
          {currentNodeData.type === 'decision' && currentNodeData.options && (
            <div className="space-y-3">
              <h4 className="font-medium text-gray-900 flex items-center gap-2">
                <Lightbulb className="h-4 w-4 text-yellow-500" />
                What is your next action?
              </h4>
              {currentNodeData.options.map(option => {
                const isSelected = selectedOptions[currentNode] === option.id;
                const showingConsequences = showConsequences[currentNode];

                return (
                  <div key={option.id} className="space-y-2">
                    <button
                      onClick={() => makeDecision(option.id)}
                      disabled={showingConsequences}
                      className={`w-full text-left p-4 border rounded-lg transition-colors ${
                        isSelected
                          ? 'border-blue-500 bg-blue-50'
                          : 'border-gray-200 hover:border-gray-300 hover:bg-gray-50'
                      } ${showingConsequences ? 'cursor-not-allowed opacity-75' : 'cursor-pointer'}`}
                    >
                      <div className="flex items-start justify-between">
                        <span className="flex-1">{option.text}</span>
                        <div className="flex items-center gap-2 ml-4">
                          {option.is_optimal && (
                            <Badge className="bg-green-100 text-green-800">Optimal</Badge>
                          )}
                          <Badge variant="outline">+{option.points} pts</Badge>
                        </div>
                      </div>
                    </button>

                    {/* Immediate Feedback */}
                    {isSelected && showingConsequences && option.immediate_feedback && (
                      <Card
                        className={`border-l-4 ${
                          option.is_optimal
                            ? 'border-l-green-500 bg-green-50'
                            : 'border-l-yellow-500 bg-yellow-50'
                        }`}
                      >
                        <CardContent className="p-4">
                          <div className="flex items-start gap-2">
                            {option.is_optimal ? (
                              <CheckCircle className="h-5 w-5 text-green-500 mt-0.5 flex-shrink-0" />
                            ) : (
                              <AlertTriangle className="h-5 w-5 text-yellow-500 mt-0.5 flex-shrink-0" />
                            )}
                            <div>
                              <p className="text-sm font-medium mb-1">
                                {option.is_optimal ? 'Excellent Choice!' : 'Consider This...'}
                              </p>
                              <p className="text-sm">{option.immediate_feedback}</p>
                              {option.consequences && option.consequences.length > 0 && (
                                <div className="mt-2">
                                  <p className="text-xs font-medium mb-1">Consequences:</p>
                                  <ul className="text-xs space-y-1">
                                    {option.consequences.map((consequence, index) => (
                                      <li key={index} className="flex items-start gap-1">
                                        <ArrowRight className="h-3 w-3 mt-0.5 flex-shrink-0" />
                                        <span>{consequence}</span>
                                      </li>
                                    ))}
                                  </ul>
                                </div>
                              )}
                            </div>
                          </div>
                        </CardContent>
                      </Card>
                    )}
                  </div>
                );
              })}
            </div>
          )}

          {/* Outcome Display */}
          {currentNodeData.type === 'outcome' && currentNodeData.outcomes && (
            <div className="space-y-4">
              {currentNodeData.outcomes.map((outcome, index) => (
                <Card key={index} className={`border-l-4 ${getOutcomeColor(outcome.type)}`}>
                  <CardContent className="p-4">
                    <div className="flex items-start gap-2">
                      {outcome.type === 'success' && (
                        <CheckCircle className="h-5 w-5 text-green-500 mt-0.5" />
                      )}
                      {outcome.type === 'warning' && (
                        <AlertTriangle className="h-5 w-5 text-yellow-500 mt-0.5" />
                      )}
                      {outcome.type === 'error' && (
                        <XCircle className="h-5 w-5 text-red-500 mt-0.5" />
                      )}
                      <div className="flex-1">
                        <p className="font-medium mb-2">{outcome.message}</p>

                        {outcome.learning_points.length > 0 && (
                          <div className="mb-3">
                            <h5 className="text-sm font-medium mb-1">Key Learning Points:</h5>
                            <ul className="text-sm space-y-1">
                              {outcome.learning_points.map((point, pointIndex) => (
                                <li key={pointIndex} className="flex items-start gap-1">
                                  <Lightbulb className="h-3 w-3 mt-0.5 flex-shrink-0 text-yellow-500" />
                                  <span>{point}</span>
                                </li>
                              ))}
                            </ul>
                          </div>
                        )}

                        {outcome.next_actions && outcome.next_actions.length > 0 && (
                          <div>
                            <h5 className="text-sm font-medium mb-1">Recommended Next Actions:</h5>
                            <ul className="text-sm space-y-1">
                              {outcome.next_actions.map((action, actionIndex) => (
                                <li key={actionIndex} className="flex items-start gap-1">
                                  <ArrowRight className="h-3 w-3 mt-0.5 flex-shrink-0" />
                                  <span>{action}</span>
                                </li>
                              ))}
                            </ul>
                          </div>
                        )}
                      </div>
                    </div>
                  </CardContent>
                </Card>
              ))}

              {/* Final Score Summary */}
              <Card className="bg-blue-50 border-blue-200">
                <CardContent className="p-4">
                  <div className="flex items-center gap-2 mb-3">
                    <Award className="h-5 w-5 text-blue-500" />
                    <h4 className="font-medium text-blue-900">Decision Path Summary</h4>
                  </div>
                  <div className="grid grid-cols-3 gap-4 text-center">
                    <div>
                      <div className="text-lg font-bold text-blue-600">
                        {decisionPath.total_points}
                      </div>
                      <p className="text-xs text-blue-700">Total Points</p>
                    </div>
                    <div>
                      <div className="text-lg font-bold text-green-600">
                        {decisionPath.efficiency_score}%
                      </div>
                      <p className="text-xs text-green-700">Efficiency</p>
                    </div>
                    <div>
                      <div className="text-lg font-bold text-purple-600">
                        {decisionPath.clinical_reasoning_score}%
                      </div>
                      <p className="text-xs text-purple-700">Clinical Reasoning</p>
                    </div>
                  </div>
                  {isOptimalPath() && (
                    <div className="mt-3 p-2 bg-green-100 rounded text-center">
                      <p className="text-sm font-medium text-green-800">
                        ≡ƒÄë Congratulations! You followed an optimal clinical pathway.
                      </p>
                    </div>
                  )}
                </CardContent>
              </Card>
            </div>
          )}
        </CardContent>
      </Card>

      {/* Decision Path Visualization */}
      <Card>
        <CardHeader>
          <CardTitle className="flex items-center gap-2">
            <Clock className="h-5 w-5 text-gray-500" />
            Your Decision Path
          </CardTitle>
        </CardHeader>
        <CardContent>
          <div className="flex items-center gap-2 flex-wrap">
            {decisionPath.nodes.map((nodeId, index) => {
              const node = decisionTree.nodes.find(n => n.id === nodeId);
              const isCurrentNode = nodeId === currentNode;

              return (
                <div key={nodeId} className="flex items-center gap-2">
                  <Badge
                    variant={isCurrentNode ? 'default' : 'outline'}
                    className={isCurrentNode ? 'bg-blue-500' : ''}
                  >
                    {node?.title || `Node ${index + 1}`}
                  </Badge>
                  {index < decisionPath.nodes.length - 1 && (
                    <ArrowRight className="h-4 w-4 text-gray-400" />
                  )}
                </div>
              );
            })}
          </div>
        </CardContent>
      </Card>
    </div>
  );
}

'use client';

import { useState, useEffect } from 'react';
import { Card, CardContent, CardHeader, CardTitle } from '@/shared/components/ui/card';
import { Button } from '@/shared/components/ui/button';
import { Badge } from '@/shared/components/ui/badge';
import { Progress } from '@/shared/components/ui/progress';
import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/shared/components/ui/tabs';
import {
  User,
  Heart,
  Activity,
  Thermometer,
  Clock,
  CheckCircle,
  AlertCircle,
  Stethoscope,
  FileText,
  Brain,
  Target,
  Timer,
  Award,
  ArrowRight,
  ArrowLeft,
  Lightbulb,
} from 'lucide-react';
import { toast } from 'sonner';

interface PatientInfo {
  age: number;
  gender: string;
  chief_complaint: string;
  history_of_present_illness: string;
  past_medical_history?: string[];
  medications?: string[];
  allergies?: string[];
  social_history?: string;
  family_history?: string;
  vital_signs?: {
    temperature?: string;
    blood_pressure?: string;
    heart_rate?: string;
    respiratory_rate?: string;
    oxygen_saturation?: string;
    weight?: string;
    height?: string;
  };
}

interface CaseSection {
  id: string;
  type: 'history' | 'physical_exam' | 'diagnostics' | 'treatment' | 'follow_up';
  title: string;
  content: string;
  order: number;
  is_unlocked_initially?: boolean;
  unlock_conditions?: string[];
  points?: number;
}

interface DecisionPoint {
  id: string;
  section_id: string;
  question: string;
  options: {
    id: string;
    text: string;
    is_correct: boolean;
    feedback: string;
    consequences?: string;
    unlocks_sections?: string[];
    points?: number;
  }[];
  type: 'single_choice' | 'multiple_choice' | 'ranking';
  required: boolean;
}

interface ClinicalCase {
  id: string;
  title: string;
  description: string;
  complexity: 'simple' | 'moderate' | 'complex' | 'expert';
  specialty: string;
  estimated_duration_minutes: number;
  learning_objectives: string[];
  patient_info: PatientInfo;
  case_flow: {
    sections: CaseSection[];
    decision_points: DecisionPoint[];
  };
}

interface CaseAttempt {
  id: string;
  status: 'inProgress' | 'completed' | 'abandoned';
  score: number;
  max_score: number;
  percentage: number;
  progress: {
    current_section: string;
    completed_sections: string[];
    unlocked_sections: string[];
    decisions_made: {
      decision_point_id: string;
      selected_option_id: string;
      timestamp: Date;
      points_earned: number;
    }[];
    section_times: {
      section_id: string;
      time_spent: number;
    }[];
  };
}

interface InteractiveCaseInterfaceProps {
  caseId: string;
  onComplete?: (attempt: CaseAttempt) => void;
}

export function InteractiveCaseInterface({ caseId, onComplete }: InteractiveCaseInterfaceProps) {
  const [clinicalCase, setClinicalCase] = useState<ClinicalCase | null>(null);
  const [attempt, setAttempt] = useState<CaseAttempt | null>(null);
  const [currentSection, setCurrentSection] = useState<string>('');
  const [selectedAnswers, setSelectedAnswers] = useState<Record<string, string[]>>({});
  const [sectionStartTime, setSectionStartTime] = useState<number>(Date.now());
  const [loading, setLoading] = useState(true);
  const [showFeedback, setShowFeedback] = useState<Record<string, boolean>>({});

  useEffect(() => {
    loadCase();
  }, [caseId]);

  const loadCase = async () => {
    try {
      setLoading(true);
      const response = await fetch(`/api/clinical-cases/${caseId}`, {
        headers: {
          Authorization: `Bearer ${localStorage.getItem('token')}`,
        },
      });

      if (response.ok) {
        const caseData = await response.json();
        setClinicalCase(caseData);

        // Check if user has an active attempt
        if (caseData.current_attempt) {
          setAttempt(caseData.current_attempt);
          setCurrentSection(caseData.current_attempt.progress.current_section);
        } else {
          // Start new attempt
          await startNewAttempt();
        }
      } else {
        toast.error('Failed to load clinical case');
      }
    } catch (error) {
      console.error('Failed to load case:', error);
      toast.error('Failed to load clinical case');
    } finally {
      setLoading(false);
    }
  };

  const startNewAttempt = async () => {
    try {
      const response = await fetch('/api/clinical-cases/attempts', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          Authorization: `Bearer ${localStorage.getItem('token')}`,
        },
        body: JSON.stringify({ case_id: caseId }),
      });

      if (response.ok) {
        const newAttempt = await response.json();
        setAttempt(newAttempt);
        setCurrentSection(newAttempt.progress.current_section);
        setSectionStartTime(Date.now());
      } else {
        toast.error('Failed to start case attempt');
      }
    } catch (error) {
      console.error('Failed to start attempt:', error);
      toast.error('Failed to start case attempt');
    }
  };

  const submitDecision = async (decisionPointId: string, selectedOptionIds: string[]) => {
    if (!attempt) return;

    try {
      const timeSpent = Math.floor((Date.now() - sectionStartTime) / 1000);

      const response = await fetch(`/api/clinical-cases/attempts/${attempt.id}/progress`, {
        method: 'PATCH',
        headers: {
          'Content-Type': 'application/json',
          Authorization: `Bearer ${localStorage.getItem('token')}`,
        },
        body: JSON.stringify({
          current_section: currentSection,
          decision_point_id: decisionPointId,
          selected_option_id: selectedOptionIds[0], // For now, handle single selection
          time_spent: timeSpent,
        }),
      });

      if (response.ok) {
        const updatedAttempt = await response.json();
        setAttempt(updatedAttempt);
        setShowFeedback(prev => ({ ...prev, [decisionPointId]: true }));

        // Check if new sections are unlocked
        const decisionPoint = clinicalCase?.case_flow.decision_points.find(
          dp => dp.id === decisionPointId
        );
        const selectedOption = decisionPoint?.options.find(opt =>
          selectedOptionIds.includes(opt.id)
        );

        if (selectedOption?.unlocks_sections) {
          toast.success('New sections unlocked!');
        }
      } else {
        toast.error('Failed to submit decision');
      }
    } catch (error) {
      console.error('Failed to submit decision:', error);
      toast.error('Failed to submit decision');
    }
  };

  const navigateToSection = (sectionId: string) => {
    if (!attempt || !attempt.progress.unlocked_sections.includes(sectionId)) {
      toast.error('This section is not yet unlocked');
      return;
    }

    setCurrentSection(sectionId);
    setSectionStartTime(Date.now());
  };

  const getComplexityColor = (complexity: string) => {
    switch (complexity) {
      case 'simple':
        return 'bg-green-100 text-green-800';
      case 'moderate':
        return 'bg-yellow-100 text-yellow-800';
      case 'complex':
        return 'bg-orange-100 text-orange-800';
      case 'expert':
        return 'bg-red-100 text-red-800';
      default:
        return 'bg-gray-100 text-gray-800';
    }
  };

  const getSectionIcon = (type: string) => {
    switch (type) {
      case 'history':
        return <FileText className="h-4 w-4" />;
      case 'physical_exam':
        return <Stethoscope className="h-4 w-4" />;
      case 'diagnostics':
        return <Activity className="h-4 w-4" />;
      case 'treatment':
        return <Heart className="h-4 w-4" />;
      case 'follow_up':
        return <Clock className="h-4 w-4" />;
      default:
        return <FileText className="h-4 w-4" />;
    }
  };

  if (loading) {
    return (
      <div className="space-y-6">
        <Card>
          <CardContent className="p-8 text-center">
            <Brain className="h-12 w-12 mx-auto mb-4 text-blue-500 animate-pulse" />
            <h3 className="text-lg font-medium mb-2">Loading Clinical Case</h3>
            <p className="text-gray-600">Preparing your interactive medical scenario...</p>
          </CardContent>
        </Card>
      </div>
    );
  }

  if (!clinicalCase || !attempt) {
    return (
      <Card>
        <CardContent className="p-8 text-center">
          <AlertCircle className="h-12 w-12 mx-auto mb-4 text-red-500" />
          <h3 className="text-lg font-medium mb-2">Case Not Available</h3>
          <p className="text-gray-600">Unable to load the clinical case.</p>
        </CardContent>
      </Card>
    );
  }

  const currentSectionData = clinicalCase.case_flow.sections.find(s => s.id === currentSection);
  const sectionDecisionPoints = clinicalCase.case_flow.decision_points.filter(
    dp => dp.section_id === currentSection
  );
  const progress =
    (attempt.progress.completed_sections.length / clinicalCase.case_flow.sections.length) * 100;

  return (
    <div className="space-y-6">
      {/* Case Header */}
      <Card>
        <CardHeader>
          <div className="flex items-start justify-between">
            <div>
              <CardTitle className="text-xl mb-2">{clinicalCase.title}</CardTitle>
              <div className="flex items-center gap-2 mb-3">
                <Badge className={getComplexityColor(clinicalCase.complexity)}>
                  {clinicalCase.complexity}
                </Badge>
                <Badge variant="outline">{clinicalCase.specialty}</Badge>
                <div className="flex items-center gap-1 text-sm text-gray-600">
                  <Timer className="h-4 w-4" />
                  {clinicalCase.estimated_duration_minutes} min
                </div>
              </div>
              <p className="text-gray-600">{clinicalCase.description}</p>
            </div>
            <div className="text-right">
              <div className="text-2xl font-bold text-blue-600">
                {attempt.percentage.toFixed(0)}%
              </div>
              <p className="text-sm text-gray-600">Score</p>
            </div>
          </div>
          <Progress value={progress} className="h-2" />
        </CardHeader>
      </Card>

      <div className="grid grid-cols-1 lg:grid-cols-4 gap-6">
        {/* Patient Information Sidebar */}
        <div className="lg:col-span-1">
          <Card className="sticky top-6">
            <CardHeader>
              <CardTitle className="flex items-center gap-2">
                <User className="h-5 w-5" />
                Patient Information
              </CardTitle>
            </CardHeader>
            <CardContent className="space-y-4">
              <div>
                <h4 className="font-medium text-gray-900 mb-2">Demographics</h4>
                <p className="text-sm text-gray-600">
                  {clinicalCase.patient_info.age} year old {clinicalCase.patient_info.gender}
                </p>
              </div>

              <div>
                <h4 className="font-medium text-gray-900 mb-2">Chief Complaint</h4>
                <p className="text-sm text-gray-600">{clinicalCase.patient_info.chief_complaint}</p>
              </div>

              {clinicalCase.patient_info.vital_signs && (
                <div>
                  <h4 className="font-medium text-gray-900 mb-2">Vital Signs</h4>
                  <div className="space-y-1 text-sm">
                    {clinicalCase.patient_info.vital_signs.temperature && (
                      <div className="flex items-center gap-2">
                        <Thermometer className="h-3 w-3" />
                        <span>Temp: {clinicalCase.patient_info.vital_signs.temperature}</span>
                      </div>
                    )}
                    {clinicalCase.patient_info.vital_signs.blood_pressure && (
                      <div className="flex items-center gap-2">
                        <Activity className="h-3 w-3" />
                        <span>BP: {clinicalCase.patient_info.vital_signs.blood_pressure}</span>
                      </div>
                    )}
                    {clinicalCase.patient_info.vital_signs.heart_rate && (
                      <div className="flex items-center gap-2">
                        <Heart className="h-3 w-3" />
                        <span>HR: {clinicalCase.patient_info.vital_signs.heart_rate}</span>
                      </div>
                    )}
                  </div>
                </div>
              )}

              {/* Section Navigation */}
              <div>
                <h4 className="font-medium text-gray-900 mb-2">Case Sections</h4>
                <div className="space-y-1">
                  {clinicalCase.case_flow.sections
                    .sort((a, b) => a.order - b.order)
                    .map(section => {
                      const isUnlocked = attempt.progress.unlocked_sections.includes(section.id);
                      const isCompleted = attempt.progress.completed_sections.includes(section.id);
                      const isCurrent = currentSection === section.id;

                      return (
                        <button
                          key={section.id}
                          onClick={() => navigateToSection(section.id)}
                          disabled={!isUnlocked}
                          className={`w-full flex items-center gap-2 p-2 rounded text-left text-sm transition-colors ${
                            isCurrent
                              ? 'bg-blue-100 text-blue-900'
                              : isUnlocked
                                ? 'hover:bg-gray-100 text-gray-700'
                                : 'text-gray-400 cursor-not-allowed'
                          }`}
                        >
                          {getSectionIcon(section.type)}
                          <span className="flex-1">{section.title}</span>
                          {isCompleted && <CheckCircle className="h-3 w-3 text-green-500" />}
                        </button>
                      );
                    })}
                </div>
              </div>
            </CardContent>
          </Card>
        </div>

        {/* Main Case Content */}
        <div className="lg:col-span-3">
          {currentSectionData && (
            <Card>
              <CardHeader>
                <CardTitle className="flex items-center gap-2">
                  {getSectionIcon(currentSectionData.type)}
                  {currentSectionData.title}
                </CardTitle>
              </CardHeader>
              <CardContent className="space-y-6">
                <div className="prose max-w-none">
                  <div dangerouslySetInnerHTML={{ __html: currentSectionData.content }} />
                </div>

                {/* Decision Points */}
                {sectionDecisionPoints.map(decisionPoint => (
                  <Card key={decisionPoint.id} className="border-l-4 border-l-blue-500">
                    <CardHeader>
                      <CardTitle className="text-lg flex items-center gap-2">
                        <Brain className="h-5 w-5 text-blue-500" />
                        Decision Point
                      </CardTitle>
                    </CardHeader>
                    <CardContent className="space-y-4">
                      <p className="font-medium text-gray-900">{decisionPoint.question}</p>

                      <div className="space-y-3">
                        {decisionPoint.options.map(option => {
                          const isSelected = selectedAnswers[decisionPoint.id]?.includes(option.id);
                          const showingFeedback = showFeedback[decisionPoint.id];

                          return (
                            <div key={option.id} className="space-y-2">
                              <label
                                className={`flex items-start p-4 border rounded-lg cursor-pointer transition-colors ${
                                  isSelected
                                    ? showingFeedback
                                      ? option.is_correct
                                        ? 'border-green-500 bg-green-50'
                                        : 'border-red-500 bg-red-50'
                                      : 'border-blue-500 bg-blue-50'
                                    : 'border-gray-200 hover:border-gray-300'
                                }`}
                              >
                                <input
                                  type={
                                    decisionPoint.type === 'single_choice' ? 'radio' : 'checkbox'
                                  }
                                  name={decisionPoint.id}
                                  value={option.id}
                                  checked={isSelected}
                                  onChange={e => {
                                    if (decisionPoint.type === 'single_choice') {
                                      setSelectedAnswers(prev => ({
                                        ...prev,
                                        [decisionPoint.id]: [option.id],
                                      }));
                                    } else {
                                      setSelectedAnswers(prev => {
                                        const current = prev[decisionPoint.id] || [];
                                        return {
                                          ...prev,
                                          [decisionPoint.id]: e.target.checked
                                            ? [...current, option.id]
                                            : current.filter(id => id !== option.id),
                                        };
                                      });
                                    }
                                  }}
                                  disabled={showingFeedback}
                                  className="sr-only"
                                />
                                <div className="flex-1">
                                  <span className="text-gray-900">{option.text}</span>
                                  {showingFeedback && isSelected && (
                                    <div
                                      className={`mt-2 p-3 rounded ${
                                        option.is_correct
                                          ? 'bg-green-100 text-green-800'
                                          : 'bg-red-100 text-red-800'
                                      }`}
                                    >
                                      <div className="flex items-start gap-2">
                                        {option.is_correct ? (
                                          <CheckCircle className="h-4 w-4 mt-0.5 flex-shrink-0" />
                                        ) : (
                                          <AlertCircle className="h-4 w-4 mt-0.5 flex-shrink-0" />
                                        )}
                                        <span className="text-sm">{option.feedback}</span>
                                      </div>
                                    </div>
                                  )}
                                </div>
                              </label>
                            </div>
                          );
                        })}
                      </div>

                      {!showFeedback[decisionPoint.id] && (
                        <Button
                          onClick={() =>
                            submitDecision(
                              decisionPoint.id,
                              selectedAnswers[decisionPoint.id] || []
                            )
                          }
                          disabled={!selectedAnswers[decisionPoint.id]?.length}
                          className="w-full"
                        >
                          Submit Decision
                        </Button>
                      )}
                    </CardContent>
                  </Card>
                ))}
              </CardContent>
            </Card>
          )}
        </div>
      </div>
    </div>
  );
}

'use client';

import { useEffect, useState } from 'react';
import { performanceMonitor } from '@/features/analytics/services/performanceMonitor';
import {
  LineChart,
  Line,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip,
  Legend,
  ResponsiveContainer,
} from 'recharts';

interface MetricData {
  timestamp: number;
  value: number;
  name: string;
}

export function PerformanceDashboard() {
  const [metrics, setMetrics] = useState<MetricData[]>([]);
  const [pageLoadMetrics, setPageLoadMetrics] = useState<any[]>([]);
  const [apiMetrics, setApiMetrics] = useState<any[]>([]);
  const [resourceMetrics, setResourceMetrics] = useState<any[]>([]);

  useEffect(() => {
    const updateMetrics = () => {
      const allMetrics = performanceMonitor.getMetrics();
      const formattedMetrics = allMetrics.map(metric => ({
        timestamp: Date.now(),
        value: metric.value,
        name: metric.name,
      }));
      setMetrics(formattedMetrics);

      const pageLoads = performanceMonitor.getPageLoadMetrics();
      setPageLoadMetrics(pageLoads);

      const apis = performanceMonitor.getApiMetrics();
      setApiMetrics(apis);

      const resources = performanceMonitor.getResourceMetrics();
      setResourceMetrics(resources);
    };

    // Update metrics every second
    const interval = setInterval(updateMetrics, 1000);
    updateMetrics();

    return () => clearInterval(interval);
  }, []);

  return (
    <div className="p-6 space-y-8 bg-gray-50/50 dark:bg-slate-900/50 min-h-screen">
      <h1 className="text-2xl font-bold mb-6 text-gray-900 dark:text-white">Performance Dashboard</h1>

      {/* Page Load Metrics */}
      <div className="bg-white/80 dark:bg-slate-800/50 backdrop-blur-sm rounded-lg shadow-sm border border-gray-100 dark:border-slate-700/50 p-6">
        <h2 className="text-xl font-semibold mb-4 text-gray-900 dark:text-white">Page Load Performance</h2>
        <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
          {pageLoadMetrics[0] && (
            <>
              <MetricCard title="Load Time" value={`${pageLoadMetrics[0].loadTime.toFixed(2)}ms`} />
              <MetricCard
                title="First Contentful Paint"
                value={`${pageLoadMetrics[0].firstContentfulPaint.toFixed(2)}ms`}
              />
              <MetricCard
                title="Largest Contentful Paint"
                value={`${pageLoadMetrics[0].largestContentfulPaint.toFixed(2)}ms`}
              />
              <MetricCard
                title="Time to Interactive"
                value={`${pageLoadMetrics[0].timeToInteractive.toFixed(2)}ms`}
              />
            </>
          )}
        </div>
      </div>

      {/* API Performance */}
      <div className="bg-white/80 dark:bg-slate-800/50 backdrop-blur-sm rounded-lg shadow-sm border border-gray-100 dark:border-slate-700/50 p-6">
        <h2 className="text-xl font-semibold mb-4 text-gray-900 dark:text-white">API Performance</h2>
        <div className="h-80">
          <ResponsiveContainer width="100%" height="100%">
            <LineChart data={apiMetrics}>
              <CartesianGrid strokeDasharray="3 3" />
              <XAxis dataKey="timestamp" />
              <YAxis />
              <Tooltip />
              <Legend />
              <Line type="monotone" dataKey="duration" stroke="#8884d8" name="Duration (ms)" />
            </LineChart>
          </ResponsiveContainer>
        </div>
      </div>

      {/* Resource Loading */}
      <div className="bg-white/80 dark:bg-slate-800/50 backdrop-blur-sm rounded-lg shadow-sm border border-gray-100 dark:border-slate-700/50 p-6">
        <h2 className="text-xl font-semibold mb-4 text-gray-900 dark:text-white">Resource Loading</h2>
        <div className="overflow-x-auto">
          <table className="min-w-full">
            <thead>
              <tr className="border-b border-gray-100 dark:border-slate-700/50">
                <th className="px-4 py-2 text-left text-gray-900 dark:text-white">Resource</th>
                <th className="px-4 py-2 text-left text-gray-900 dark:text-white">Type</th>
                <th className="px-4 py-2 text-left text-gray-900 dark:text-white">Size (KB)</th>
                <th className="px-4 py-2 text-left text-gray-900 dark:text-white">Load Time (ms)</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-gray-100 dark:divide-slate-700/50">
              {resourceMetrics.map((resource, index) => (
                <tr key={index}>
                  <td className="px-4 py-2 text-gray-600 dark:text-slate-300">{resource.name}</td>
                  <td className="px-4 py-2 text-gray-600 dark:text-slate-300">{resource.type}</td>
                  <td className="px-4 py-2 text-gray-600 dark:text-slate-300">{(resource.size / 1024).toFixed(2)}</td>
                  <td className="px-4 py-2 text-gray-600 dark:text-slate-300">{resource.loadTime.toFixed(2)}</td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>

      {/* Custom Metrics */}
      <div className="bg-white/80 dark:bg-slate-800/50 backdrop-blur-sm rounded-lg shadow-sm border border-gray-100 dark:border-slate-700/50 p-6">
        <h2 className="text-xl font-semibold mb-4 text-gray-900 dark:text-white">Custom Metrics</h2>
        <div className="h-80">
          <ResponsiveContainer width="100%" height="100%">
            <LineChart data={metrics}>
              <CartesianGrid strokeDasharray="3 3" />
              <XAxis dataKey="timestamp" />
              <YAxis />
              <Tooltip />
              <Legend />
              <Line type="monotone" dataKey="value" stroke="#82ca9d" name="Value" />
            </LineChart>
          </ResponsiveContainer>
        </div>
      </div>
    </div>
  );
}

function MetricCard({ title, value }: { title: string; value: string }) {
  return (
    <div className="bg-gray-50/50 dark:bg-slate-900/50 rounded-lg p-4 border border-gray-100 dark:border-slate-700/50">
      <h3 className="text-sm font-medium text-gray-500 dark:text-slate-400">{title}</h3>
      <p className="text-2xl font-semibold text-gray-900 dark:text-white">{value}</p>
    </div>
  );
}

import React, { useState, useEffect } from 'react';
import { useRapidReview } from '@/shared/hooks/useRapidReview';
import { Button } from '@/shared/components/ui/button';
import { Progress } from '@/shared/components/ui/progress';
import { Badge } from '@/shared/components/ui/badge';
import { Clock, Zap, Target, CheckCircle, XCircle, RotateCcw, Timer } from 'lucide-react';

interface RapidReviewSessionProps {
  userId: string;
  topics?: string[];
}

const RAPID_REVIEW_TIME_LIMIT = 10 * 60; // 10 minutes in seconds
const QUESTION_TIME_LIMIT = 30; // 30 seconds per question

export function RapidReviewSession({ userId, topics }: RapidReviewSessionProps) {
  const {
    questions,
    currentIndex,
    currentQuestion,
    answers,
    isLoading,
    error,
    sessionComplete,
    answerQuestion,
    resetSession,
    startSession,
    isStarted,
    sessionStartTime,
  } = useRapidReview(userId, topics);

  const [showAnswer, setShowAnswer] = useState(false);
  const [timeRemaining, setTimeRemaining] = useState(RAPID_REVIEW_TIME_LIMIT);
  const [questionTimeRemaining, setQuestionTimeRemaining] = useState(QUESTION_TIME_LIMIT);
  const [selectedAnswer, setSelectedAnswer] = useState<string>('');
  const [showExplanation, setShowExplanation] = useState(false);

  // Timer effects
  useEffect(() => {
    if (!isStarted || sessionComplete) return;

    const timer = setInterval(() => {
      setTimeRemaining(prev => {
        if (prev <= 1) {
          // Time's up - auto-complete session
          return 0;
        }
        return prev - 1;
      });
    }, 1000);

    return () => clearInterval(timer);
  }, [isStarted, sessionComplete]);

  useEffect(() => {
    if (!isStarted || sessionComplete || !currentQuestion) return;

    setQuestionTimeRemaining(QUESTION_TIME_LIMIT);
    const timer = setInterval(() => {
      setQuestionTimeRemaining(prev => {
        if (prev <= 1) {
          // Auto-skip question if time runs out
          handleAutoSkip();
          return QUESTION_TIME_LIMIT;
        }
        return prev - 1;
      });
    }, 1000);

    return () => clearInterval(timer);
  }, [currentIndex, isStarted, sessionComplete]);

  const formatTime = (seconds: number): string => {
    const minutes = Math.floor(seconds / 60);
    const remainingSeconds = seconds % 60;
    return `${minutes}:${remainingSeconds.toString().padStart(2, '0')}`;
  };

  const handleAutoSkip = () => {
    if (currentQuestion) {
      answerQuestion(currentQuestion.id, false, 0); // Mark as incorrect with 0 time
      setSelectedAnswer('');
      setShowExplanation(false);
    }
  };

  const handleAnswerSelect = (answer: string, isCorrect: boolean) => {
    const timeSpent = QUESTION_TIME_LIMIT - questionTimeRemaining;
    answerQuestion(currentQuestion.id, isCorrect, timeSpent);
    setSelectedAnswer('');
    setShowExplanation(false);
  };

  if (isLoading) {
    return (
      <div className="text-center space-y-4">
        <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-blue-600 mx-auto"></div>
        <div className="text-blue-500 dark:text-blue-400">Loading rapid review questions...</div>
      </div>
    );
  }

  if (error) {
    return (
      <div className="text-center space-y-4">
        <XCircle className="h-12 w-12 text-red-500 mx-auto" />
        <div className="text-red-500">{error.message}</div>
        <Button onClick={() => window.location.reload()} variant="outline">
          Try Again
        </Button>
      </div>
    );
  }

  if (!currentQuestion && !sessionComplete && !isStarted) {
    return (
      <div className="text-center space-y-6">
        <div className="space-y-2">
          <Zap className="h-16 w-16 text-yellow-500 dark:text-yellow-400 mx-auto" />
          <h2 className="text-2xl font-bold text-gray-900 dark:text-white">Ready for Rapid Review?</h2>
          <p className="text-gray-600 dark:text-slate-400 max-w-md mx-auto">
            10 high-yield questions in 10 minutes. Perfect for last-minute review and reinforcing
            weak areas.
          </p>
        </div>

        <div className="grid grid-cols-3 gap-4 max-w-md mx-auto">
          <div className="text-center">
            <Target className="h-8 w-8 text-blue-500 dark:text-blue-400 mx-auto mb-2" />
            <div className="text-sm font-medium text-gray-900 dark:text-slate-200">10 Questions</div>
            <div className="text-xs text-gray-500 dark:text-slate-500">High-yield topics</div>
          </div>
          <div className="text-center">
            <Timer className="h-8 w-8 text-green-500 dark:text-green-400 mx-auto mb-2" />
            <div className="text-sm font-medium text-gray-900 dark:text-slate-200">10 Minutes</div>
            <div className="text-xs text-gray-500 dark:text-slate-500">Time limit</div>
          </div>
          <div className="text-center">
            <CheckCircle className="h-8 w-8 text-purple-500 dark:text-purple-400 mx-auto mb-2" />
            <div className="text-sm font-medium text-gray-900 dark:text-slate-200">Instant Feedback</div>
            <div className="text-xs text-gray-500 dark:text-slate-500">Learn as you go</div>
          </div>
        </div>

        <Button
          onClick={startSession}
          size="lg"
          className="bg-yellow-500 hover:bg-yellow-600 text-white"
        >
          <Zap className="h-5 w-5 mr-2" />
          Start Rapid Review
        </Button>
      </div>
    );
  }

  if (sessionComplete) {
    const correctCount = answers.filter(a => a.correct).length;
    const totalTime = sessionStartTime ? Math.round((Date.now() - sessionStartTime) / 1000) : 0;
    const averageTime =
      answers.length > 0
        ? Math.round(answers.reduce((sum, a) => sum + (a.timeSpent || 0), 0) / answers.length)
        : 0;
    const percentage = Math.round((correctCount / questions.length) * 100);

    const getScoreColor = (score: number) => {
      if (score >= 80) return 'text-green-600 dark:text-green-400';
      if (score >= 60) return 'text-yellow-600 dark:text-yellow-400';
      return 'text-red-600 dark:text-red-400';
    };

    const getScoreBadgeColor = (score: number) => {
      if (score >= 80) return 'bg-green-100 dark:bg-green-500/20 text-green-800 dark:text-green-400';
      if (score >= 60) return 'bg-yellow-100 dark:bg-yellow-500/20 text-yellow-800 dark:text-yellow-400';
      return 'bg-red-100 dark:bg-red-500/20 text-red-800 dark:text-red-400';
    };

    return (
      <div className="text-center space-y-6">
        <div className="space-y-2">
          <CheckCircle className="h-16 w-16 text-green-500 dark:text-green-400 mx-auto" />
          <h2 className="text-2xl font-bold text-gray-900 dark:text-white">Rapid Review Complete!</h2>
        </div>

        <div className="grid grid-cols-2 gap-4 max-w-md mx-auto">
          <div className="bg-white/80 dark:bg-slate-800/50 backdrop-blur-sm rounded-lg p-4 border border-gray-100 dark:border-slate-700/50">
            <div className={`text-2xl font-bold ${getScoreColor(percentage)}`}>
              {correctCount}/{questions.length}
            </div>
            <div className="text-sm text-gray-500 dark:text-slate-400">Questions Correct</div>
            <Badge className={`mt-2 ${getScoreBadgeColor(percentage)}`}>{percentage}%</Badge>
          </div>

          <div className="bg-white/80 dark:bg-slate-800/50 backdrop-blur-sm rounded-lg p-4 border border-gray-100 dark:border-slate-700/50">
            <div className="text-2xl font-bold text-blue-600 dark:text-blue-400">{formatTime(totalTime)}</div>
            <div className="text-sm text-gray-500 dark:text-slate-400">Total Time</div>
            <div className="text-xs text-gray-400 dark:text-slate-500 mt-1">Avg: {averageTime}s per question</div>
          </div>
        </div>

        {percentage < 70 && (
          <div className="bg-yellow-50 dark:bg-yellow-500/10 border border-yellow-200 dark:border-yellow-500/20 rounded-lg p-4 max-w-md mx-auto">
            <div className="text-sm text-yellow-800 dark:text-yellow-400">
              <strong>Tip:</strong> Consider reviewing the topics you missed before your next study
              session.
            </div>
          </div>
        )}

        <div className="flex gap-3 justify-center">
          <Button onClick={resetSession} variant="outline">
            <RotateCcw className="h-4 w-4 mr-2" />
            Try Again
          </Button>
          <Button onClick={() => (window.location.href = '/dashboard')}>Back to Dashboard</Button>
        </div>
      </div>
    );
  }

  // MCQ or short answer logic
  const isMCQ = currentQuestion.options && Array.isArray(currentQuestion.options);
  const progressPercentage = ((currentIndex + 1) / questions.length) * 100;

  return (
    <div className="w-full max-w-2xl mx-auto space-y-4">
      {/* Header with timers and progress */}
      <div className="bg-white/80 dark:bg-slate-800/50 backdrop-blur-sm rounded-lg p-4 shadow-sm border border-gray-100 dark:border-slate-700/50">
        <div className="flex items-center justify-between mb-3">
          <div className="flex items-center gap-4">
            <Badge variant="outline" className="text-sm dark:border-slate-700 dark:text-slate-300">
              Question {currentIndex + 1} / {questions.length}
            </Badge>
            {currentQuestion.topic && (
              <Badge className="bg-blue-100 dark:bg-blue-500/20 text-blue-800 dark:text-blue-400 text-xs">{currentQuestion.topic}</Badge>
            )}
          </div>

          <div className="flex items-center gap-4">
            <div className="flex items-center gap-2 text-sm">
              <Clock className="h-4 w-4 text-gray-500 dark:text-slate-400" />
              <span
                className={`font-mono ${questionTimeRemaining <= 10 ? 'text-red-600 dark:text-red-400 font-bold' : 'text-gray-700 dark:text-slate-300'}`}
              >
                {questionTimeRemaining}s
              </span>
            </div>
            <div className="flex items-center gap-2 text-sm">
              <Timer className="h-4 w-4 text-blue-500 dark:text-blue-400" />
              <span className="font-mono text-blue-600 dark:text-blue-300">{formatTime(timeRemaining)}</span>
            </div>
          </div>
        </div>

        <Progress value={progressPercentage} className="h-2" />
      </div>

      {/* Question card */}
      <div className="bg-white/80 dark:bg-slate-800/50 backdrop-blur-sm rounded-xl shadow-sm border border-gray-100 dark:border-slate-700/50 p-6">
        <div className="mb-6">
          <h2 className="text-xl font-semibold text-gray-900 dark:text-white leading-relaxed">
            {currentQuestion.question_text}
          </h2>
        </div>

        {isMCQ ? (
          <div className="space-y-3">
            {currentQuestion.options.map((opt: string, idx: number) => (
              <Button
                key={opt}
                className="w-full text-left justify-start p-4 h-auto min-h-12 hover:bg-blue-50 dark:hover:bg-blue-900/20 hover:border-blue-300 dark:hover:border-blue-700 dark:text-slate-200"
                variant="outline"
                onClick={() => handleAnswerSelect(opt, opt === currentQuestion.correctAnswer)}
              >
                <span className="flex items-start gap-3 w-full">
                  <span className="shrink-0 w-6 h-6 rounded-full bg-gray-100 dark:bg-slate-700 flex items-center justify-center text-sm font-medium text-gray-900 dark:text-slate-200">
                    {String.fromCharCode(65 + idx)}
                  </span>
                  <span className="text-left">{opt}</span>
                </span>
              </Button>
            ))}
          </div>
        ) : (
          <div className="space-y-4">
            {showAnswer ? (
              <div className="p-4 bg-blue-50 dark:bg-blue-950/30 border border-blue-200 dark:border-blue-800 rounded-lg">
                <div className="font-semibold text-blue-900 dark:text-blue-300 mb-2">Correct Answer:</div>
                <div className="text-blue-800 dark:text-blue-400">{currentQuestion.correctAnswer}</div>
                {currentQuestion.explanation && (
                  <div className="mt-3 pt-3 border-t border-blue-200 dark:border-blue-800">
                    <div className="font-semibold text-blue-900 dark:text-blue-300 mb-1">Explanation:</div>
                    <div className="text-blue-700 dark:text-blue-500 text-sm">{currentQuestion.explanation}</div>
                  </div>
                )}
              </div>
            ) : null}

            {!showAnswer ? (
              <Button
                className="w-full bg-blue-600 hover:bg-blue-700"
                onClick={() => setShowAnswer(true)}
                size="lg"
              >
                Show Answer
              </Button>
            ) : (
              <div className="flex gap-3">
                <Button
                  variant="outline"
                  className="flex-1 border-red-200 dark:border-red-800 text-red-700 dark:text-red-400 hover:bg-red-50 dark:hover:bg-red-950/20"
                  onClick={() => handleAnswerSelect('wrong', false)}
                  size="lg"
                >
                  <XCircle className="h-4 w-4 mr-2" />I got it wrong
                </Button>
                <Button
                  className="flex-1 bg-green-600 hover:bg-green-700 text-white"
                  onClick={() => handleAnswerSelect('correct', true)}
                  size="lg"
                >
                  <CheckCircle className="h-4 w-4 mr-2" />I got it right
                </Button>
              </div>
            )}
          </div>
        )}
      </div>
    </div>
  );
}

