'use client';

import React, { useEffect, useState } from 'react';
import { Card, CardContent, CardHeader, CardTitle } from '@/shared/components/ui/card';
import { Button } from '@/shared/components/ui/button';
import { Switch } from '@/shared/components/ui/switch';
import { Label } from '@/shared/components/ui/label';
import {
  getTwoFactorAuthStatus,
  enableTwoFactorAuth,
  disableTwoFactorAuth,
} from '@/features/auth/services/securityService';

import type { TwoFactorAuthStatus } from '@/shared/types/systemInterface';
import { Lock } from 'lucide-react';

export const TwoFactorAuth: React.FC = () => {
  const [status, setStatus] = useState<TwoFactorAuthStatus | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [isUpdating, setIsUpdating] = useState(false);

  const fetchStatus = async () => {
    try {
      const fetchedStatus = await getTwoFactorAuthStatus();
      setStatus(fetchedStatus);
    } catch (err) {
      setError('Failed to fetch 2FA status.');
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchStatus();
  }, []);

  const handleToggle2FA = async (checked: boolean) => {
    setIsUpdating(true);
    try {
      if (checked) {
        // In a real app, this would trigger a flow to set up 2FA (e.g., QR code, SMS verification)
        // For mock, we'll just enable it with a default method
        const updatedStatus = await enableTwoFactorAuth('app');
        setStatus(updatedStatus);
        alert('Two-factor authentication enabled!');
      } else {
        const updatedStatus = await disableTwoFactorAuth();
        setStatus(updatedStatus);
        alert('Two-factor authentication disabled.');
      }
    } catch (err) {
      setError('Failed to update 2FA status.');
      console.error(err);
    } finally {
      setIsUpdating(false);
    }
  };

  if (loading) {
    return (
      <Card>
        <CardContent className="p-6 text-center">Loading 2FA status...</CardContent>
      </Card>
    );
  }

  if (error) {
    return (
      <Card>
        <CardContent className="p-6 text-center text-red-500">Error: {error}</CardContent>
      </Card>
    );
  }

  return (
    <Card>
      <CardHeader>
        <CardTitle className="flex items-center">
          <Lock className="mr-2" /> Two-Factor Authentication
        </CardTitle>
      </CardHeader>
      <CardContent className="space-y-4">
        <div className="flex items-center justify-between">
          <Label htmlFor="2fa-switch" className="text-base">
            Enable 2FA
          </Label>
          <Switch
            id="2fa-switch"
            checked={status?.enabled}
            onCheckedChange={handleToggle2FA}
            disabled={isUpdating}
          />
        </div>
        {status?.enabled ? (
          <p className="text-sm text-muted-foreground">
            2FA is currently enabled using the <strong>{status.method}</strong> method.
            {status.lastEnabledAt && (
              <span> Last enabled on {new Date(status.lastEnabledAt).toLocaleDateString()}.</span>
            )}
          </p>
        ) : (
          <p className="text-sm text-muted-foreground">
            Two-factor authentication adds an extra layer of security to your account.
          </p>
        )}
        {isUpdating && <p className="text-sm text-blue-500">Updating 2FA status...</p>}
      </CardContent>
    </Card>
  );
};

import { useSession } from 'next-auth/react';
import { hasPermission } from '@/features/auth/services/rbacService';
import { UserRole, Permission } from '@/shared/types';
import { UseAuthReturn } from '@/shared/types/authInterface';
import { useState, useEffect } from 'react';

/**
 * Custom hook for checking user roles and permissions on the client-side.
 *
 * @param requiredPermission Optional. The permission required for a specific action or component.
 * @returns An object with the user's role, loading state, and a boolean indicating if they have the required role.
 */
export const useRBAC = (requiredPermission?: Permission) => {
  const { data: session, status } = useSession();
  const isLoading = status === 'loading';
  const [data, setData] = useState<any>(null);
  const [error, setError] = useState<Error | null>(null);

  const userRole = (session?.user?.role as UserRole) || 'guest'; // Default to 'guest' if role is undefined
  const userPermissions = (session?.user?.permissions as string[]) || [];

  useEffect(() => {
    // If no permission is specified, this hook acts as a roles/permissions fetcher
    if (!requiredPermission) {
      // In a real implementation, this would fetch roles from the backend
      // For now, we'll return the user's role/permissions from session
      setData(session?.user || null);
      if (error) setError(null);
    }
  }, [session, requiredPermission]);

  // Check if the user has the required permission
  const hasRequiredPermission = requiredPermission
    ? hasPermission(
        { role: userRole, permissions: userPermissions },
        requiredPermission as unknown as string
      )
    : true;

  return {
    /** The role of the currently authenticated user. Defaults to 'guest'. */
    role: userRole,
    /** `true` if the session is still being fetched. */
    isLoading,
    /** `true` if the user has the required permission. */
    hasRequiredPermission,
    /** Data returned when no permission is specified (for RBACAdminPanel) */
    data,
    /** Error when fetching data */
    error,
  };
};

import axios, { AxiosInstance, type AxiosRequestConfig, type AxiosResponse } from 'axios';
import { signIn, signOut, getSession } from 'next-auth/react';
import { ApiError, ApiResponse, RequestOptions } from '@/shared/types';
import { errorService } from '@/app/services/error.service';

// Enhanced error classification
type ErrorType = 'network' | 'timeout' | 'auth' | 'validation' | 'server' | 'unknown';

interface EnhancedApiError extends ApiError {
  errorType: ErrorType;
  isRetryable: boolean;
  timestamp: string;
  url?: string;
  method?: string;
}

class ApiService {
  private static instance: ApiService;
  private api: AxiosInstance;
  private refreshTokenPromise: Promise<boolean> | null = null;

  private static buildApiBaseUrl(): string {
    // Use backend URL with /v1 prefix directly
    const backendUrl = process.env.NEXT_PUBLIC_API_URL || 'http://localhost:3002';
    return `${backendUrl}/v1`;
  }

  private constructor() {
    const baseURL = ApiService.buildApiBaseUrl();
    this.api = axios.create({
      baseURL,
      timeout: 30000,
      withCredentials: true,
    });

    this.setupInterceptors();
  }

  static getInstance(): ApiService {
    if (!ApiService.instance) {
      ApiService.instance = new ApiService();
    }
    return ApiService.instance;
  }

  /**
   * Classify error type for better handling and logging
   */
  private classifyError(error: unknown): ErrorType {
    if (error instanceof axios.AxiosError) {
      if (!error.response) {
        // Network error
        if (error.code === 'ECONNABORTED' || error.message === 'timeout of 30000ms exceeded') {
          return 'timeout';
        }
        return 'network';
      }

      const status = error.response.status;
      if (status === 401 || status === 403) {
        return 'auth';
      }
      if (status === 400 || status === 422) {
        return 'validation';
      }
      if (status >= 500) {
        return 'server';
      }
      return 'unknown';
    }
    return 'unknown';
  }

  /**
   * Determine if an error is retryable
   */
  private isRetryable(errorType: ErrorType, status?: number): boolean {
    if (errorType === 'timeout' || errorType === 'network') {
      return true;
    }
    if (errorType === 'server' && status && status >= 500 && status < 599) {
      // Retry on server errors except 501 Not Implemented
      return status !== 501;
    }
    return false;
  }

  private setupInterceptors(): void {
    // Request interceptor
    this.api.interceptors.request.use(
      async config => {
        try {
          const session = await getSession();
          if (session?.accessToken) {
            // Ensure headers object exists
            config.headers = config.headers || {};
            config.headers.Authorization = `Bearer ${session.accessToken}`;
            config.headers['Content-Type'] = 'application/json';
            // Add credentials
            config.withCredentials = true;
          } else {
            // Don't warn for public endpoints like /auth/login, /auth/register
            if (!config.url?.includes('/auth/')) {
              console.warn('No access token found in session for request to:', config.url);
            }
          }
          return config;
        } catch (error) {
          console.error('[Request Interceptor] Failed to set auth headers:', error);
          return Promise.reject(error);
        }
      },
      error => {
        console.error('[Request Interceptor] Unexpected error:', error);
        return Promise.reject(error);
      }
    );

    // Response interceptor
    this.api.interceptors.response.use(
      response => response,
      async error => {
        const originalRequest = error.config;
        const errorType = this.classifyError(error);

        // --- OFFLINE SYNC INTEGRATION START ---
        // Identify if this is a mutation (POST, PUT, PATCH, DELETE) that failed due to network
        // Note: 503 is also often a temporary server issue worth queuing
        const isMutation = ['POST', 'PUT', 'PATCH', 'DELETE'].includes(
          originalRequest.method?.toUpperCase()
        );
        const isNetworkOrServerTemp =
          errorType === 'network' || errorType === 'timeout' || error.response?.status === 503;

        if (isMutation && isNetworkOrServerTemp) {
          try {
            // Lazy load syncService to separate imports slightly (optional but safe)
            const { syncService } = await import('@/lib/core/offline/syncService');

            console.log(
              `[Offline] Queuing mutation: ${originalRequest.method} ${originalRequest.url}`
            );

            // Queue request
            await syncService.addToOutbox(
              originalRequest.url,
              originalRequest.method.toUpperCase(),
              originalRequest.data
                ? typeof originalRequest.data === 'string'
                  ? JSON.parse(originalRequest.data)
                  : originalRequest.data
                : undefined,
              originalRequest.headers // Includes Auth headers
            );

            // Return "Optimistic Success"
            // The UI should handle this gracefully by checking for an 'offline' flag if needed
            // or we just return a standard success structure.
            return {
              data: {
                success: true,
                message: 'Operation queued for offline sync',
                offline: true, // Marker for UI
                queuedAt: new Date().toISOString(),
              },
              status: 200,
              statusText: 'OK (Offline Queued)',
              headers: {},
              config: originalRequest,
            };
          } catch (queueError) {
            console.error('[Offline] Failed to queue request', queueError);
            // Fall through to normal error handling
          }
        }
        // --- OFFLINE SYNC INTEGRATION END ---

        // Handle token refresh for 401s except for auth endpoints
        if (
          errorType === 'auth' &&
          error.response?.status === 401 &&
          !originalRequest._retry &&
          !originalRequest.url?.includes('/auth/')
        ) {
          originalRequest._retry = true;
          console.warn('[Token Refresh] Token expired, attempting refresh...');

          try {
            // Ensure only one token refresh request is in flight
            if (!this.refreshTokenPromise) {
              this.refreshTokenPromise = this.performTokenRefresh();
            }

            const refreshSuccess = await this.refreshTokenPromise;
            this.refreshTokenPromise = null;

            if (refreshSuccess) {
              console.warn('[Token Refresh] Token refresh successful, retrying original request');
              // Get the new token and update the request
              const newSession = await getSession();
              if (newSession?.accessToken) {
                originalRequest.headers = originalRequest.headers || {};
                originalRequest.headers.Authorization = `Bearer ${newSession.accessToken}`;
                return this.api(originalRequest);
              }
            }

            // If we get here, refresh failed
            console.error('[Token Refresh] Token refresh failed, signing out');
            await signOut({ redirect: false });
            return Promise.reject(
              this.createEnhancedError(error, 'Session expired. Please log in again.', 'auth')
            );
          } catch (refreshError) {
            console.error('[Token Refresh] Token refresh error:', refreshError);
            this.refreshTokenPromise = null;
            await signOut({ redirect: false });
            return Promise.reject(refreshError);
          }
        }

        // Transform error response
        const enhancedError = this.createEnhancedError(
          error,
          error.response?.data?.message,
          errorType
        );
        // Pass the enhanced error directly to the error service for centralized handling and logging
        errorService.handleApiError({
          ...enhancedError,
          endpoint: originalRequest?.url,
          method: originalRequest?.method?.toUpperCase(),
        });

        return Promise.reject(enhancedError);
      }
    );
  }

  /**
   * Perform token refresh via NextAuth
   */
  private async performTokenRefresh(): Promise<boolean> {
    try {
      const session = await getSession();
      const currentToken = session?.accessToken;

      if (!currentToken) {
        return false;
      }

      // Try to refresh session using NextAuth
      const result = await signIn('credentials', {
        redirect: false,
        identifier: 'refresh',
        password: 'refresh',
        headers: {
          Authorization: `Bearer ${currentToken}`,
        },
      });

      return result?.ok === true;
    } catch (error: unknown) {
      const err = error instanceof Error ? error.message : String(error);
      console.error('[Token Refresh] Refresh attempt failed:', err);
      return false;
    }
  }

  /**
   * Create enhanced error object with full context
   */
  private createEnhancedError(
    error: unknown,
    message?: string,
    errorType?: ErrorType
  ): EnhancedApiError {
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    const err = error as any;
    const status = err?.response?.status ?? err?.status ?? 500;
    const classifiedErrorType = errorType || this.classifyError(error);
    const isRetryable = this.isRetryable(classifiedErrorType, status);

    const errorDetails = {
      ...(err?.response?.data?.details ?? {}),
      ...(err?.response?.data?.validationErrors
        ? { validationErrors: err.response.data.validationErrors }
        : {}),
      ...(err?.response?.statusText ? { statusText: err.response.statusText } : {}),
    };

    return {
      code: err?.response?.data?.code ?? err?.code ?? 'UNKNOWN_ERROR',
      message:
        message ?? err?.response?.data?.message ?? err?.message ?? 'An unexpected error occurred',
      details: Object.keys(errorDetails).length > 0 ? errorDetails : undefined,
      status,
      errorType: classifiedErrorType,
      isRetryable,
      timestamp: new Date().toISOString(),
      url: err?.config?.url,
      method: err?.config?.method?.toUpperCase(),
    };
  }

  async get<T>(url: string, options?: RequestOptions): Promise<ApiResponse<T>> {
    try {
      const config: AxiosRequestConfig = {
        headers: options?.headers,
        params: options?.params,
        timeout: options?.timeout,
        withCredentials: options?.withCredentials,
        responseType: options?.responseType,
      };

      const response: AxiosResponse<ApiResponse<T>> = await this.api.get(url, config);
      return response.data;
    } catch (error) {
      if (error instanceof Error && 'isRetryable' in error) {
        // Already enhanced error, just rethrow
        throw error;
      }
      throw this.createEnhancedError(error);
    }
  }

  async post<T>(url: string, data?: unknown, options?: RequestOptions): Promise<ApiResponse<T>> {
    try {
      const config: AxiosRequestConfig = {
        headers: options?.headers,
        params: options?.params,
        timeout: options?.timeout,
        withCredentials: options?.withCredentials,
        responseType: options?.responseType,
        onUploadProgress: options?.onUploadProgress
          ? (progressEvent: import('axios').AxiosProgressEvent) => {
              // Normalize and forward to the provided handler. Use a loose cast because
              // handlers in callers may accept browser ProgressEvent or AxiosProgressEvent.
              (options.onUploadProgress as unknown as (ev: unknown) => void)(
                progressEvent as unknown
              );
            }
          : undefined,
      };

      const response: AxiosResponse<ApiResponse<T>> = await this.api.post(url, data, config);
      return response.data;
    } catch (error) {
      if (error instanceof Error && 'isRetryable' in error) {
        throw error;
      }
      throw this.createEnhancedError(error);
    }
  }

  async put<T>(url: string, data?: unknown, options?: RequestOptions): Promise<ApiResponse<T>> {
    try {
      const config: AxiosRequestConfig = {
        headers: options?.headers,
        params: options?.params,
        timeout: options?.timeout,
        withCredentials: options?.withCredentials,
        responseType: options?.responseType,
      };

      const response: AxiosResponse<ApiResponse<T>> = await this.api.put(url, data, config);
      return response.data;
    } catch (error) {
      if (error instanceof Error && 'isRetryable' in error) {
        throw error;
      }
      throw this.createEnhancedError(error);
    }
  }

  async patch<T>(url: string, data?: unknown, options?: RequestOptions): Promise<ApiResponse<T>> {
    try {
      const config: AxiosRequestConfig = {
        headers: options?.headers,
        params: options?.params,
        timeout: options?.timeout,
        withCredentials: options?.withCredentials,
        responseType: options?.responseType,
      };

      const response: AxiosResponse<ApiResponse<T>> = await this.api.patch(url, data, config);
      return response.data;
    } catch (error) {
      if (error instanceof Error && 'isRetryable' in error) {
        throw error;
      }
      throw this.createEnhancedError(error);
    }
  }

  async delete<T>(url: string, options?: RequestOptions): Promise<ApiResponse<T>> {
    try {
      const config: AxiosRequestConfig = {
        headers: options?.headers,
        params: options?.params,
        timeout: options?.timeout,
        withCredentials: options?.withCredentials,
      };

      const response: AxiosResponse<ApiResponse<T>> = await this.api.delete(url, config);
      return response.data;
    } catch (error) {
      if (error instanceof Error && 'isRetryable' in error) {
        throw error;
      }
      throw this.createEnhancedError(error);
    }
  }
}

