        <div className="space-y-4">
          {pathAnalytics.milestone_analytics.map((milestone, index) => (
            <div key={index} className="border border-gray-200 rounded-lg p-4">
              <div className="flex items-center justify-between mb-3">
                <h4 className="font-medium text-gray-900">{milestone.title}</h4>
                <div className="flex items-center space-x-2">
                  <Award className="w-4 h-4 text-yellow-600" />
                  <span className="text-sm font-medium text-gray-600">
                    {formatPercentage(milestone.achievement_rate)} achieved
                  </span>
                </div>
              </div>

              <div className="w-full bg-gray-200 rounded-full h-2 mb-2">
                <div
                  className="bg-yellow-600 h-2 rounded-full transition-all duration-300"
                  style={{ width: `${milestone.achievement_rate}%` }}
                />
              </div>

              <div className="text-sm text-gray-600">
                Average time to achieve: {formatDays(milestone.average_time_to_achieve)}
              </div>
            </div>
          ))}
        </div>
      ) : (
        <div className="text-center py-8">
          <Award className="w-12 h-12 text-gray-400 mx-auto mb-4" />
          <p className="text-gray-500">No milestone data available</p>
        </div>
      )}
    </div>
  );

  const renderInsightsTab = () => (
    <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
      {/* Learning Velocity */}
      <div className="bg-white rounded-lg shadow-sm border border-gray-200 p-6">
        <h3 className="text-lg font-semibold text-gray-900 mb-4">Your Learning Velocity</h3>
        <div className="flex items-center space-x-4">
          <div className="p-3 bg-blue-100 rounded-lg">
            <Zap className="w-6 h-6 text-blue-600" />
          </div>
          <div>
            <div className="text-2xl font-bold text-gray-900">
              {userInsights?.learning_velocity.toFixed(1)}x
            </div>
            <div className="text-sm text-gray-600">
              {(userInsights?.learning_velocity || 0) > 1
                ? 'Faster than average'
                : 'Take your time'}
            </div>
          </div>
        </div>
      </div>

      {/* Goal Achievement */}
      <div className="bg-white rounded-lg shadow-sm border border-gray-200 p-6">
        <h3 className="text-lg font-semibold text-gray-900 mb-4">Goal Achievement</h3>
        <div className="flex items-center space-x-4">
          <div className="p-3 bg-green-100 rounded-lg">
            <Target className="w-6 h-6 text-green-600" />
          </div>
          <div>
            <div className="text-2xl font-bold text-gray-900">
              {formatPercentage(userInsights?.goal_achievement_rate || 0)}
            </div>
            <div className="text-sm text-gray-600">Success rate</div>
          </div>
        </div>
      </div>

      {/* Strongest Categories */}
      <div className="bg-white rounded-lg shadow-sm border border-gray-200 p-6">
        <h3 className="text-lg font-semibold text-gray-900 mb-4">Your Strengths</h3>
        <div className="space-y-2">
          {userInsights?.strongest_categories.map((category, index) => (
            <div key={index} className="px-3 py-2 bg-green-100 text-green-800 rounded-lg text-sm">
              {category.replace('_', ' ')}
            </div>
          ))}
        </div>
      </div>

      {/* Improvement Areas */}
      <div className="bg-white rounded-lg shadow-sm border border-gray-200 p-6">
        <h3 className="text-lg font-semibold text-gray-900 mb-4">Areas for Improvement</h3>
        <div className="space-y-2">
          {userInsights?.improvement_areas.map((area, index) => (
            <div key={index} className="px-3 py-2 bg-yellow-100 text-yellow-800 rounded-lg text-sm">
              {area.replace('_', ' ')}
            </div>
          ))}
        </div>
      </div>

      {/* Recommended Next Steps */}
      <div className="bg-white rounded-lg shadow-sm border border-gray-200 p-6 md:col-span-2">
        <h3 className="text-lg font-semibold text-gray-900 mb-4">Recommended Next Steps</h3>
        <div className="space-y-3">
          {userInsights?.recommended_next_steps.map((step, index) => (
            <div key={index} className="flex items-start space-x-3 p-3 bg-blue-50 rounded-lg">
              <div className="w-6 h-6 bg-blue-600 text-white rounded-full flex items-center justify-center text-sm font-medium">
                {index + 1}
              </div>
              <div className="text-sm text-gray-700">{step}</div>
