};

'use client';

import React, { useState, useEffect } from 'react';
import {
  Sparkles,
  TrendingUp,
  Users,
  Star,
  Clock,
  Target,
  BookOpen,
  ChevronRight,
  Lightbulb,
  Award,
  Brain,
} from 'lucide-react';

interface RecommendationScore {
  path_id: string;
  score: number;
  reasons: string[];
  confidence: number;
  estimated_completion_time: number;
  learning_path?: {
    id: string;
    title: string;
    description: string;
    category: string;
    difficulty: string;
    estimated_duration_weeks: number;
    analytics: {
      total_enrollments: number;
      completion_rate: number;
      user_ratings: {
        average: number;
        count: number;
      };
    };
  };
}

interface LearningPathRecommendationsProps {
  userId?: string;
  limit?: number;
  showTrending?: boolean;
  showCollaborative?: boolean;
}

export const LearningPathRecommendations: React.FC<LearningPathRecommendationsProps> = ({
  userId,
  limit = 6,
  showTrending = true,
  showCollaborative = true,
}) => {
  const [personalizedRecs, setPersonalizedRecs] = useState<RecommendationScore[]>([]);
  const [collaborativeRecs, setCollaborativeRecs] = useState<RecommendationScore[]>([]);
  const [trendingPaths, setTrendingPaths] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [activeTab, setActiveTab] = useState<'personalized' | 'collaborative' | 'trending'>(
    'personalized'
  );

  useEffect(() => {
    fetchRecommendations();
  }, [userId, limit]);

  const fetchRecommendations = async () => {
    try {
      setLoading(true);

      // Fetch personalized recommendations
      const personalizedResponse = await fetch(
        `/api/learning-paths/recommendations?limit=${limit}`
      );
      if (personalizedResponse.ok) {
        const personalizedData = await personalizedResponse.json();
        // Fetch full path details for each recommendation
        const enrichedPersonalized = await Promise.all(
          personalizedData.map(async (rec: RecommendationScore) => {
            try {
              const pathResponse = await fetch(`/api/learning-paths/${rec.path_id}`);
              if (pathResponse.ok) {
                const pathData = await pathResponse.json();
                return { ...rec, learning_path: pathData };
              }
              return rec;
            } catch (error) {
              return rec;
            }
          })
        );
        setPersonalizedRecs(enrichedPersonalized);
      }

      // Fetch collaborative recommendations if enabled
      if (showCollaborative) {
        const collaborativeResponse = await fetch(
          `/api/learning-paths/recommendations/collaborative?limit=${Math.ceil(limit / 2)}`
        );
        if (collaborativeResponse.ok) {
          const collaborativeData = await collaborativeResponse.json();
          const enrichedCollaborative = await Promise.all(
            collaborativeData.map(async (rec: RecommendationScore) => {
              try {
                const pathResponse = await fetch(`/api/learning-paths/${rec.path_id}`);
                if (pathResponse.ok) {
                  const pathData = await pathResponse.json();
                  return { ...rec, learning_path: pathData };
                }
                return rec;
              } catch (error) {
                return rec;
              }
            })
          );
          setCollaborativeRecs(enrichedCollaborative);
        }
      }

      // Fetch trending paths if enabled
      if (showTrending) {
        const trendingResponse = await fetch(
          `/api/learning-paths/trending?limit=${Math.ceil(limit / 2)}`
        );
        if (trendingResponse.ok) {
          const trendingData = await trendingResponse.json();
          setTrendingPaths(trendingData);
        }
      }
    } catch (error) {
      console.error('Error fetching recommendations:', error);
    } finally {
      setLoading(false);
    }
  };

  const getDifficultyColor = (difficulty: string) => {
    switch (difficulty.toLowerCase()) {
      case 'beginner':
        return 'bg-green-100 text-green-800';
      case 'intermediate':
        return 'bg-yellow-100 text-yellow-800';
      case 'advanced':
        return 'bg-orange-100 text-orange-800';
      case 'expert':
        return 'bg-red-100 text-red-800';
      default:
        return 'bg-gray-100 text-gray-800';
    }
  };

  const getConfidenceColor = (confidence: number) => {
    if (confidence >= 0.8) return 'text-green-600';
    if (confidence >= 0.6) return 'text-yellow-600';
    return 'text-gray-600';
  };

  const renderRecommendationCard = (
    rec: RecommendationScore,
    type: 'personalized' | 'collaborative' | 'trending'
  ) => {
    const path = rec.learning_path;
    if (!path) return null;

    return (
      <div
        key={rec.path_id}
        className="bg-white rounded-lg shadow-sm border border-gray-200 hover:shadow-md transition-shadow p-6"
      >
        <div className="flex items-start justify-between mb-4">
          <div className="flex-1">
            <h3 className="text-lg font-semibold text-gray-900 mb-2">{path.title}</h3>
            <p className="text-gray-600 text-sm mb-3 line-clamp-2">{path.description}</p>

            <div className="flex flex-wrap gap-2 mb-3">
              <span
                className={`px-2 py-1 rounded-full text-xs font-medium ${getDifficultyColor(path.difficulty)}`}
              >
                {path.difficulty}
              </span>
              <span className="px-2 py-1 rounded-full text-xs font-medium bg-blue-100 text-blue-800">
                {path.category.replace('_', ' ')}
              </span>
            </div>
          </div>

          <div className="flex flex-col items-end space-y-2">
            <div className="flex items-center space-x-1">
              <Star className="w-4 h-4 text-yellow-400 fill-current" />
              <span className="text-sm text-gray-600">
                {path.analytics.user_ratings.average.toFixed(1)}
              </span>
            </div>

            {type === 'personalized' && (
              <div className={`text-sm font-medium ${getConfidenceColor(rec.confidence)}`}>
                {Math.round(rec.score)}% match
              </div>
            )}
          </div>
        </div>

        {/* Recommendation reasons */}
        {rec.reasons && rec.reasons.length > 0 && (
          <div className="mb-4">
            <div className="flex items-center space-x-2 mb-2">
              <Lightbulb className="w-4 h-4 text-blue-600" />
              <span className="text-sm font-medium text-gray-700">Why this path?</span>
            </div>
            <ul className="space-y-1">
              {rec.reasons.slice(0, 2).map((reason, index) => (
                <li key={index} className="text-sm text-gray-600 flex items-start space-x-2">
                  <span className="w-1 h-1 bg-blue-600 rounded-full mt-2 flex-shrink-0"></span>
                  <span>{reason}</span>
                </li>
              ))}
            </ul>
          </div>
        )}

        {/* Path stats */}
        <div className="flex items-center justify-between text-sm text-gray-500 mb-4">
          <div className="flex items-center space-x-4">
            <div className="flex items-center space-x-1">
              <Clock className="w-4 h-4" />
              <span>{path.estimated_duration_weeks}w</span>
            </div>
            <div className="flex items-center space-x-1">
              <Users className="w-4 h-4" />
              <span>{path.analytics.total_enrollments}</span>
            </div>
            <div className="flex items-center space-x-1">
              <TrendingUp className="w-4 h-4" />
              <span>{Math.round(path.analytics.completion_rate)}%</span>
            </div>
          </div>

          {rec.estimated_completion_time && (
            <div className="flex items-center space-x-1 text-blue-600">
              <Target className="w-4 h-4" />
              <span>~{rec.estimated_completion_time}w for you</span>
            </div>
          )}
        </div>

        {/* Confidence indicator */}
        {type === 'personalized' && (
          <div className="mb-4">
            <div className="flex items-center justify-between text-sm text-gray-600 mb-1">
              <span>Recommendation confidence</span>
              <span>{Math.round(rec.confidence * 100)}%</span>
            </div>
            <div className="w-full bg-gray-200 rounded-full h-2">
              <div
                className={`h-2 rounded-full transition-all duration-300 ${
                  rec.confidence >= 0.8
                    ? 'bg-green-600'
                    : rec.confidence >= 0.6
                      ? 'bg-yellow-600'
                      : 'bg-gray-600'
                }`}
                style={{ width: `${rec.confidence * 100}%` }}
              />
            </div>
          </div>
        )}

        {/* Action button */}
        <button className="w-full flex items-center justify-center space-x-2 bg-blue-600 text-white px-4 py-2 rounded-lg hover:bg-blue-700 transition-colors">
          <BookOpen className="w-4 h-4" />
          <span>View Learning Path</span>
          <ChevronRight className="w-4 h-4" />
        </button>
      </div>
    );
  };

  const renderTrendingCard = (path: any) => (
    <div
      key={path.id}
      className="bg-white rounded-lg shadow-sm border border-gray-200 hover:shadow-md transition-shadow p-6"
    >
      <div className="flex items-start justify-between mb-4">
        <div className="flex-1">
          <h3 className="text-lg font-semibold text-gray-900 mb-2">{path.title}</h3>
          <p className="text-gray-600 text-sm mb-3 line-clamp-2">{path.description}</p>

          <div className="flex flex-wrap gap-2 mb-3">
            <span
              className={`px-2 py-1 rounded-full text-xs font-medium ${getDifficultyColor(path.difficulty)}`}
            >
              {path.difficulty}
            </span>
            <span className="px-2 py-1 rounded-full text-xs font-medium bg-purple-100 text-purple-800">
              Trending
            </span>
          </div>
        </div>

        <div className="flex items-center space-x-1 text-yellow-400">
          <Star className="w-4 h-4 fill-current" />
          <span className="text-sm text-gray-600">
            {path.analytics?.user_ratings?.average?.toFixed(1) || 'New'}
          </span>
        </div>
      </div>

      <div className="flex items-center justify-between text-sm text-gray-500 mb-4">
        <div className="flex items-center space-x-4">
          <div className="flex items-center space-x-1">
            <Clock className="w-4 h-4" />
            <span>{path.estimated_duration_weeks}w</span>
          </div>
          <div className="flex items-center space-x-1">
            <Users className="w-4 h-4" />
            <span>{path.analytics?.total_enrollments || 0}</span>
          </div>
        </div>

        <div className="flex items-center space-x-1 text-green-600">
          <TrendingUp className="w-4 h-4" />
          <span>Popular this month</span>
        </div>
