'use client';

import React, { useState, useEffect } from 'react';
import {
  Award,
  Star,
  Trophy,
  Target,
  CheckCircle,
  Gift,
  Share2,
  Download,
  X,
  Sparkles,
  Medal,
  Crown,
} from 'lucide-react';

interface Milestone {
  id: string;
  title: string;
  description: string;
  type: string;
  rewards?: {
    points?: number;
    badge_id?: string;
    certificate?: {
      template_id: string;
      title: string;
      description: string;
    };
    unlock_content?: {
      courses?: string[];
      assessments?: string[];
      clinical_cases?: string[];
    };
  };
  celebration_config?: {
    show_animation: boolean;
    animation_type: 'confetti' | 'fireworks' | 'badge' | 'custom';
    message: string;
    auto_share: boolean;
  };
}

interface MilestoneCelebrationProps {
  milestone: Milestone;
  isVisible: boolean;
  onClose: () => void;
  onShare?: () => void;
  onDownloadCertificate?: () => void;
}

export const MilestoneCelebration: React.FC<MilestoneCelebrationProps> = ({
  milestone,
  isVisible,
  onClose,
  onShare,
  onDownloadCertificate,
}) => {
  const [showConfetti, setShowConfetti] = useState(false);
