                >
                  <ThumbsDown className="h-4 w-4 mr-2" />
                  Hard
                </Button>
                <Button
                  variant="outline"
                  className="flex-1"
                  onClick={() => {
                    rateCard(3); // Good
                    setShowAnswer(false);
                  }}
                >
                  <ThumbsUp className="h-4 w-4 mr-2" />
                  Good
                </Button>
                <Button
                  className="flex-1 bg-green-600 hover:bg-green-700"
                  onClick={() => {
                    rateCard(5); // Easy
                    setShowAnswer(false);
                  }}
                >
                  <CheckCircle2 className="h-4 w-4 mr-2" />
                  Easy
                </Button>
              </div>
            </div>
          ) : (
            <Button className="w-full" onClick={() => setShowAnswer(true)}>
              Show Answer
            </Button>
          )}
        </div>
      </Card>
    </div>
  );
}

