export const StudyDashboard: React.FC = () => {
  const { user } = useAuthStore();
  const { getStudyStats, getTopicsByCategory, getCourseProgress, getUnitProgress } = useStudy();
  const { getPeerStats } = usePeerBenchmarking();

  const [stats, setStats] = useState<StudyStats | null>(null);
  const [topics, setTopics] = useState<any[]>([]);
  const [courseProgress, setCourseProgress] = useState<any[]>([]);
  const [unitProgress, setUnitProgress] = useState<any[]>([]);
  const [peerStats, setPeerStats] = useState<any>(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const loadDashboard = async () => {
      try {
        const [statsData, topicsData, courseData, unitData] = await Promise.all([
          getStudyStats(),
          getTopicsByCategory(),
          getCourseProgress(),
          getUnitProgress(),
        ]);
        setStats(statsData);
        setTopics(
          Object.keys(topicsData).map(key => ({
            id: key,
            title: key,
            // topicsData may be an array or simple structure; default to 0%
            completionPercentage: 0,
          }))
        );
        setCourseProgress(courseData);
        setUnitProgress(unitData);

        const topicKeys = Object.keys(topicsData);
        if (topicKeys.length > 0) {
          const peerData = await getPeerStats();
          setPeerStats(peerData);
        }
      } catch (error) {
        console.error('Error loading dashboard:', error);
      } finally {
        setLoading(false);
      }
    };

    loadDashboard();
  }, []);

  if (loading) {
    return (
      <div className="flex justify-center items-center min-h-[60vh]">
        <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-blue-500 mx-auto mb-4" />
        <p className="text-gray-600 dark:text-slate-400">Loading...</p>
      </div>
    );
  }

  // Format lastUpdated timestamp for display
  const formatLastUpdated = (timestamp?: number): string => {
    if (!timestamp) return 'Not synced';
    const now = Date.now();
    const diffMs = now - timestamp;
    const diffMins = Math.floor(diffMs / 60000);
    if (diffMins < 1) return 'Just now';
    if (diffMins < 60) return `${diffMins}m ago`;
    const diffHours = Math.floor(diffMins / 60);
    if (diffHours < 24) return `${diffHours}h ago`;
    const diffDays = Math.floor(diffHours / 24);
    return `${diffDays}d ago`;
  };

  return (
    <div className="p-3 bg-gray-50/50 dark:bg-slate-900/50 min-h-screen">
      {/* Stats Overview */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-3 mb-4">
        <div className="bg-white/80 dark:bg-slate-800/50 backdrop-blur-sm rounded-lg shadow-sm border border-gray-100 dark:border-slate-700/50 p-4">
          <h6 className="text-lg font-semibold mb-2 text-gray-900 dark:text-white">Study Streak</h6>
          <p className="text-4xl font-bold text-blue-600 dark:text-blue-400">{stats?.currentStreak || 0}</p>
          <p className="text-sm text-gray-500 dark:text-slate-400">days</p>
        </div>
        <div className="bg-white/80 dark:bg-slate-800/50 backdrop-blur-sm rounded-lg shadow-sm border border-gray-100 dark:border-slate-700/50 p-4">
          <h6 className="text-lg font-semibold mb-2 text-gray-900 dark:text-white">Total Study Time</h6>
          <p className="text-4xl font-bold text-blue-600 dark:text-blue-400">
            {Math.round((stats?.totalTime || 0) / 60)}h
          </p>
          <p className="text-sm text-gray-500 dark:text-slate-400">this week</p>
        </div>
