import React, { useState, useEffect } from 'react';
import { useStudy } from '../hooks/useStudy';
import { Card, CardContent } from '@/shared/components/ui/card';
import { Button } from '@/shared/components/ui/button';
import { Progress } from '@/shared/components/ui/progress';
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogFooter,
  DialogTitle,
} from '@/shared/components/ui/dialog';
import { Label } from '@/shared/components/ui/label';
import { Textarea } from '@/shared/components/ui/textarea';
import { ScrollArea } from '@/shared/components/ui/scroll-area';
import { Play, Pause, Square, Timer, BookOpen, Sparkles, ScrollText } from 'lucide-react';
import { useTheme } from '@/app/providers';

interface StudySessionProps {
  topicId: string;
  onSessionEnd: () => void;
}

export const StudySession: React.FC<StudySessionProps> = ({ topicId, onSessionEnd }) => {
  const { startSession, endSession } = useStudy();
  const theme = useTheme();

  const [sessionId, setSessionId] = useState<string | null>(null);
  const [isActive, setIsActive] = useState(false);
  const [elapsedTime, setElapsedTime] = useState(0);
  const [activities, setActivities] = useState<any[]>([]);
  const [showEndDialog, setShowEndDialog] = useState(false);
  const [notes, setNotes] = useState('');

  useEffect(() => {
    let timer: NodeJS.Timeout;
    if (isActive) {
      timer = setInterval(() => {
        setElapsedTime((prev: number) => prev + 1);
      }, 1000);
    }
    return () => clearInterval(timer);
  }, [isActive]);

  const handleStart = async () => {
    try {
      const session = await startSession(topicId);
      setSessionId(session.id);
      setIsActive(true);
    } catch (error) {
      console.error('Error starting session:', error);
    }
  };

  const handlePause = () => {
    setIsActive(false);
  };

  const handleResume = () => {
    setIsActive(true);
  };

  const handleStop = () => {
    setShowEndDialog(true);
  };

  const handleEndSession = async () => {
    if (!sessionId) return;

    try {
      await endSession(sessionId, undefined, notes);
      onSessionEnd();
    } catch (error) {
      console.error('Error ending session:', error);
    }
  };

  const addActivity = (type: string) => {
    setActivities(prev => [
      ...prev,
      {
        type,
        durationMinutes: Math.floor(elapsedTime / 60),
        timestamp: new Date(),
      },
    ]);
  };

  const formatTime = (seconds: number) => {
    const hours = Math.floor(seconds / 3600);
    const minutes = Math.floor((seconds % 3600) / 60);
    const secs = seconds % 60;
    return `${hours.toString().padStart(2, '0')}:${minutes.toString().padStart(2, '0')}:${secs.toString().padStart(2, '0')}`;
  };

  return (
    <div>
      <Card>
        <CardContent className="space-y-6">
          <div className="flex items-center justify-between">
            <h2 className="text-2xl font-semibold">Study Session</h2>
            <div className="text-3xl font-mono text-blue-600 dark:text-blue-400">
              {formatTime(elapsedTime)}
            </div>
          </div>

          <div className="flex justify-center gap-4">
            {!isActive ? (
              <Button onClick={handleStart} className="w-40">
                <Play className="h-4 w-4 mr-2" />
                Start Session
              </Button>
            ) : (
              <>
                <Button variant="outline" onClick={handlePause} className="w-32">
                  <Pause className="h-4 w-4 mr-2" />
                  Pause
                </Button>
                <Button variant="destructive" onClick={handleStop} className="w-32">
                  <Square className="h-4 w-4 mr-2" />
                  End Session
                </Button>
              </>
            )}
          </div>

          <div className="flex justify-center gap-4">
            <Button
              variant="ghost"
              size="icon"
              onClick={() => addActivity('reading')}
              title="Add Reading Activity"
              className="h-10 w-10"
            >
              <BookOpen className="h-5 w-5" />
            </Button>
            <Button
              variant="ghost"
              size="icon"
              onClick={() => addActivity('quiz')}
              title="Add Quiz Activity"
              className="h-10 w-10"
            >
              <Sparkles className="h-5 w-5" />
            </Button>
            <Button
              variant="ghost"
              size="icon"
              onClick={() => addActivity('notes')}
              title="Add Notes Activity"
              className="h-10 w-10"
            >
              <ScrollText className="h-5 w-5" />
            </Button>
          </div>

          {activities.length > 0 && (
            <div>
              <h3 className="text-lg font-medium mb-2">Activities</h3>
              <ScrollArea className="h-[200px] rounded-md border p-4">
                <div className="space-y-2">
                  {activities.map((activity, index) => (
                    <div key={index} className="flex items-center gap-2 text-sm">
                      {activity.type === 'reading' && <BookOpen className="h-4 w-4" />}
                      {activity.type === 'quiz' && <Sparkles className="h-4 w-4" />}
                      {activity.type === 'notes' && <ScrollText className="h-4 w-4" />}
                      <span>
                        {activity.type.charAt(0).toUpperCase() + activity.type.slice(1)} -{' '}
                        {activity.durationMinutes} minutes
                      </span>
                    </div>
                  ))}
                </div>
              </ScrollArea>
            </div>
          )}
        </CardContent>
      </Card>

      <Dialog open={showEndDialog} onOpenChange={open => setShowEndDialog(open)}>
        <DialogContent>
          <DialogHeader>
            <DialogTitle>End Study Session</DialogTitle>
          </DialogHeader>
          <div className="space-y-4">
            <div>
              <Label>Session Duration</Label>
              <p className="text-lg font-mono text-blue-600 dark:text-blue-400">
                {formatTime(elapsedTime)}
              </p>
            </div>
            <div className="space-y-2">
              <Label htmlFor="notes">Session Notes</Label>
              <Textarea
                id="notes"
                value={notes}
                onChange={e => setNotes(e.target.value)}
                placeholder="Write your session notes here..."
                className="min-h-[100px]"
              />
            </div>
          </div>
          <DialogFooter>
            <Button variant="outline" onClick={() => setShowEndDialog(false)}>
              Cancel
            </Button>
            <Button onClick={handleEndSession}>End Session</Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </div>
  );
};

import { useState, useEffect } from 'react';
import { useAuthStore } from '@/features/auth/store/useAuthStore';
import progressService from '../../services/progressService';
import type { StudyStats, CourseProgressData, UnitProgressData } from '@/shared/types/progressInterface';

// Internal type for hook state - represents a user's study session tracking (different from StudySession which is group-based)
interface StudySessionInternal {
  id: string;
  userId: string;
  startTime: Date;
  endTime?: Date;
  duration: number; // in minutes
  topic: string;
  score?: number;
  notes?: string;
}

export const useStudy = () => {
  const { user } = useAuthStore();
  const [sessions, setSessions] = useState<StudySessionInternal[]>([]);
  const [stats, setStats] = useState<StudyStats>({
    totalSessions: 0,
    totalTime: 0,
    averageScore: 0,
    currentStreak: 0,
    topicsStudied: [],
    courseProgress: [],
    unitProgress: [],
  });
  const [isLoading, setIsLoading] = useState(false);

  // Dummy data for courses and units
  const dummyCourses: CourseProgressData[] = [
    { id: 'course-1', name: 'Advanced Medical Terminology', progressPercentage: 75 },
    { id: 'course-2', name: 'Clinical Anatomy Basics', progressPercentage: 40 },
    { id: 'course-3', name: 'Pharmacology Fundamentals', progressPercentage: 90 },
  ];

  const [dummyUnits, setDummyUnits] = useState<UnitProgressData[]>([
    { id: 'unit-1-1', name: 'Cardiovascular System', courseId: 'course-1', progressPercentage: 80 },
    { id: 'unit-1-2', name: 'Respiratory System', courseId: 'course-1', progressPercentage: 60 },
    { id: 'unit-2-1', name: 'Skeletal System', courseId: 'course-2', progressPercentage: 45 },
    { id: 'unit-3-1', name: 'Drug Interactions', courseId: 'course-3', progressPercentage: 95 },
  ]);

  const startSession = async (topic: string): Promise<StudySessionInternal> => {
    const session: StudySessionInternal = {
      id: Date.now().toString(),
      userId: 'current-user', // This should come from auth context
      startTime: new Date(),
      duration: 0,
      topic,
    };

    setSessions(prev => [...prev, session]);
    return session;
  };

  const endSession = async (sessionId: string, score?: number, notes?: string): Promise<void> => {
    setSessions(prev =>
      prev.map(session =>
        session.id === sessionId
          ? {
              ...session,
              endTime: new Date(),
              duration: session.endTime
                ? (session.endTime.getTime() - session.startTime.getTime()) / 1000 / 60
                : 0,
              score,
              notes,
            }
          : session
      )
    );
  };

  const getStats = (): void => {
    const completedSessions = sessions.filter(s => s.endTime);
    const totalSessions = completedSessions.length;
    const totalTime = completedSessions.reduce((sum, s) => sum + (s.duration || 0), 0);
    const averageScore =
      completedSessions.length > 0
        ? completedSessions.reduce((sum, s) => sum + (s.score || 0), 0) / completedSessions.length
        : 0;
    const topicsStudied = [...new Set(completedSessions.map(s => s.topic))];

    setStats({
      totalSessions,
      totalTime,
      averageScore,
      currentStreak: 0, // This would need to be calculated based on daily sessions
      topicsStudied,
      courseProgress: dummyCourses, // Add dummy course progress
      unitProgress: dummyUnits, // Add dummy unit progress
    });
  };

  useEffect(() => {
    getStats();
  }, [sessions]);

  const getStudyStats = async (): Promise<StudyStats> => {
    if (!user?.id) return stats;

    try {
      setIsLoading(true);
      const [progressData, streakData] = await Promise.all([
        progressService.getProgressStats(user.id).catch(() => null),
        progressService.getUserStreaks(user.id).catch(() => null),
      ]);

      const updatedStats: StudyStats = {
        totalSessions: (progressData?.totalSessions as number) ?? stats.totalSessions,
        totalTime: (progressData?.totalTime as number) ?? stats.totalTime,
        averageScore: (progressData?.averageScore as number) ?? stats.averageScore,
        currentStreak: streakData?.currentStreak ?? progressData?.streak ?? stats.currentStreak,
        topicsStudied: stats.topicsStudied,
        courseProgress: stats.courseProgress,
        unitProgress: stats.unitProgress,
      };

      setStats(updatedStats);
      return updatedStats;
    } catch (error) {
      console.error('Error fetching study stats:', error);
      return stats;
    } finally {
      setIsLoading(false);
    }
  };

  const getTopicsByCategory = (): Record<string, string[]> => {
    const topicsByCategory: Record<string, string[]> = {};
    sessions.forEach(session => {
      if (!topicsByCategory[session.topic]) {
        topicsByCategory[session.topic] = [];
      }
    });
    return topicsByCategory;
  };

  const getCourseProgress = async (): Promise<CourseProgressData[]> => {
    if (!user?.id) return dummyCourses;

    try {
      const response = await progressService.getCourseProgress(user.id);
      if (Array.isArray(response) && response.length > 0) {
        return response.map((course: any) => ({
          id: course.id || course.courseId || '',
          name: course.name || course.courseName || course.title || '',
          progressPercentage: course.progressPercentage || course.progress || 0,
        }));
      }
      return dummyCourses;
    } catch (error) {
      console.error('Error fetching course progress:', error);
      return dummyCourses;
    }
  };

  const getUnitProgress = async (courseId?: string): Promise<UnitProgressData[]> => {
    if (!user?.id) return dummyUnits;

    try {
      const response = await progressService.getUnitProgress(user.id, courseId);
      if (Array.isArray(response) && response.length > 0) {
        return response.map((unit: any) => ({
          id: unit.id || unit.unitId || '',
          name: unit.name || unit.unitName || unit.title || '',
          courseId: unit.courseId || courseId || '',
          progressPercentage: unit.progressPercentage || 0,
        }));
      }
      return dummyUnits;
    } catch (error) {
      console.error('Error fetching unit progress:', error);
      return dummyUnits;
    }
  };

  return {
    sessions,
    stats,
    isLoading,
    startSession,
    endSession,
    getStats,
    getStudyStats,
    getTopicsByCategory,
    getCourseProgress,
    getUnitProgress,
  };
};

export function getNumberField<T>(obj: T | null | undefined, key: string): number | undefined {
  if (!obj) return undefined;
  const val = (obj as unknown as Record<string, unknown>)[key];
  if (typeof val === 'number') return val;
  if (typeof val === 'string') {
    const n = Number(val);
    return Number.isNaN(n) ? undefined : n;
  }
  return undefined;
}

export function getStringField<T>(obj: T | null | undefined, key: string): string | undefined {
  if (!obj) return undefined;
  const val = (obj as unknown as Record<string, unknown>)[key];
  return typeof val === 'string' ? val : undefined;
}

export function normalizeSyncStatus(val: unknown): 'error' | 'pending' | 'synced' | undefined {
  if (typeof val !== 'string') return undefined;
  const s = val.toLowerCase();
  if (s === 'error' || s === 'pending' || s === 'synced') return s as any;
  return undefined;
}

export function downloadJson(obj: unknown, filename = 'data.json') {
  const blob = new Blob([JSON.stringify(obj, null, 2)], { type: 'application/json' });
  const url = URL.createObjectURL(blob);
  const a = document.createElement('a');
  a.href = url;
  a.download = filename;
  document.body.appendChild(a);
  a.click();
  a.remove();
  URL.revokeObjectURL(url);
}

import { apiService } from '@/features/auth/services/apiClient';
import { ApiResponse } from '@/shared/types/base-responseInterface';
import { User } from '@/shared/types';
import { PaginatedResult } from '@/shared/types';
import { UserAnalytics, UserInsights } from '@/shared/types/analyticsInterface';
import { toast } from 'sonner';

const ANALYTICS_BASE_URL = '/api/analytics';

class UserService {
  private baseUrl = '/users';

  /**
   * Fetches a paginated list of users.
   */
  async getUsers(page = 1, limit = 10): Promise<PaginatedResult<User>> {
    const response = await apiService.get<ApiResponse<PaginatedResult<User>>>(this.baseUrl, {
      params: { page, limit },
    });
    return response.data.data;
  }

  /**
   * Fetches the profile of the currently authenticated user.
   */
  async getMyProfile(): Promise<User> {
    const response = await apiService.get<ApiResponse<User>>(`${this.baseUrl}/profile`);
    return response.data.data;
  }

  /**
   * Fetches a specific user by their ID.
   */
  async getUserById(userId: string): Promise<User> {
    const response = await apiService.get<ApiResponse<User>>(`${this.baseUrl}/${userId}`);
    return response.data.data;
  }

  /**
   * Fetches a specific user's profile by their ID.
   */
  async getUserProfile(userId: string): Promise<User> {
    const response = await apiService.get<ApiResponse<User>>(`${this.baseUrl}/profile/${userId}`);
    return response.data.data;
  }

  /**
   * Updates a user's profile information.
   */
  async updateUserProfile(userId: string, data: Partial<User>): Promise<User> {
    const response = await apiService.patch<ApiResponse<User>>(`${this.baseUrl}/${userId}`, data);
    return response.data.data;
  }

  /**
   * Updates the role of a specific user.
   */
  async updateUserRole(userId: string, role: string): Promise<void> {
    await apiService.put(`${this.baseUrl}/${userId}/role`, { role });
  }

  /**
   * Deletes a user by their ID.
   */
  async deleteUser(userId: string): Promise<void> {
    await apiService.delete(`${this.baseUrl}/${userId}`);
  }

  /**
   * Finds a user by their email address.
   */
  async findUserByEmail(email: string): Promise<User | null> {
    try {
      const response = await apiService.get<ApiResponse<User>>(`${this.baseUrl}/email/${email}`);
      return response.data.data;
    } catch (error) {
      // Assuming the API returns a 404 if not found
      return null;
    }
  }

  async getUserAnalytics(userId: string): Promise<UserAnalytics | null> {
    try {
      const response = await apiService.get<ApiResponse<UserAnalytics>>(
        `${ANALYTICS_BASE_URL}/user/${userId}`
      );
      return response.data.data;
    } catch (error) {
      const err = error instanceof Error ? error : new Error(String(error));
      console.error('Error fetching user analytics:', err.message, err.stack);
      toast.error('Failed to load user analytics.');
      return null;
    }
  }

  async getUserInsights(userId: string): Promise<UserInsights | null> {
    try {
      const response = await apiService.get<ApiResponse<UserInsights>>(
        `${ANALYTICS_BASE_URL}/insights/${userId}`
      );
      return response.data.data;
    } catch (error) {
      const err = error instanceof Error ? error : new Error(String(error));
      console.error('Error fetching user insights:', err.message, err.stack);
      toast.error('Failed to load user insights.');
      return null;
    }
  }
}

