'use client';

import React, { useEffect, useState, useRef, useCallback } from 'react';
import { useSearch } from '@/features/search/hooks/useSearch';
import Link from 'next/link';

interface SearchResultsProps {
  initialQuery?: string;
  initialFilter?: string;
}

export const SearchResults: React.FC<SearchResultsProps> = ({
  initialQuery = '',
  initialFilter = 'all',
}) => {
  const [query, setQuery] = useState(initialQuery);
  const [filter, setFilter] = useState(initialFilter);
  const [page, setPage] = useState(1);
  const limit = 20;
  const { results, total, loading, search } = useSearch();
  const itemRefs = useRef<Array<HTMLAnchorElement | null>>([]);
  const [focusedIndex, setFocusedIndex] = useState<number | null>(null);

  // Clear item refs when results change
  useEffect(() => {
    itemRefs.current = itemRefs.current.slice(0, results.length);
  }, [results]);

  useEffect(() => {
    if (query) {
      search(query, filter, page, limit);
    } else {
      // clear results if no query
      search('', filter, page, limit);
    }
  }, [query, filter, page, search]);

  // Keyboard navigation: focus management
  const focusItem = useCallback((index: number) => {
    const el = itemRefs.current[index];
    if (el) {
      el.focus();
      setFocusedIndex(index);
    }
  }, []);

  const handleInputKeyDown = (e: React.KeyboardEvent<HTMLInputElement>) => {
    if (e.key === 'ArrowDown' && results.length > 0) {
      e.preventDefault();
      focusItem(0);
    }
  };

  const handleListKeyDown = (e: React.KeyboardEvent<HTMLUListElement>) => {
    if (e.key === 'ArrowDown') {
      e.preventDefault();
      const next = focusedIndex === null ? 0 : Math.min(results.length - 1, focusedIndex + 1);
      focusItem(next);
    } else if (e.key === 'ArrowUp') {
      e.preventDefault();
      const prev = focusedIndex === null ? results.length - 1 : Math.max(0, focusedIndex - 1);
      focusItem(prev);
    } else if (e.key === 'Enter') {
      // Let the focused anchor handle Enter by default
    }
  };

  return (
    <div>
      <div className="mb-4 flex items-center gap-2">
        <label htmlFor="search-input" className="sr-only">
          Search query
        </label>
        <input
          id="search-input"
          type="text"
          value={query}
          onChange={e => {
            setQuery(e.target.value);
            setPage(1);
          }}
          onKeyDown={handleInputKeyDown}
          placeholder="Search for courses, materials, users..."
          aria-label="Search for courses, materials, users"
          className="flex-1 px-3 py-2 border rounded"
        />

        <div>
          <label htmlFor="search-filter" className="sr-only">
            Filter results by type
          </label>
          <select
            id="search-filter"
            value={filter}
            onChange={e => {
              setFilter(e.target.value);
              setPage(1);
            }}
            className="px-2 py-2 border rounded"
            aria-label="Filter results"
          >
            <option value="all">All</option>
            <option value="course">Courses</option>
            <option value="unit">Units</option>
            <option value="topic">Topics</option>
            <option value="material">Materials</option>
            <option value="user">Users</option>
          </select>
        </div>
      </div>

      {loading && <div>SearchingΓÇª</div>}

      {!loading && (
        <div>
          <div className="text-sm text-gray-600 mb-2">{total} results</div>
          <ul
            className="space-y-2"
            role="listbox"
            aria-label="Search results"
            onKeyDown={handleListKeyDown}
          >
            {results.map((r: any, idx: number) => {
              let href = `/profile/${r.id}`;
              if (r.type === 'course') href = `/courses/${r.id}`;
              else if (r.type === 'material') href = `/materials/${r.id}`;
              else if (r.type === 'unit') href = `/units/${r.id}`;
              else if (r.type === 'topic') href = `/topics/${r.id}`;
              return (
                <li key={`${r.type}-${r.id}`} className="p-3 border rounded">
                  <Link href={href} passHref legacyBehavior>
                    <a
                      ref={el => {
                        itemRefs.current[idx] = el;
                      }}
                      role="option"
                      aria-selected={focusedIndex === idx}
                      tabIndex={-1}
                      className="block focus:outline-none focus:ring-2 focus:ring-blue-500"
                      onFocus={() => setFocusedIndex(idx)}
                    >
                      <div className="font-medium">{r.title}</div>
                      <div className="text-sm text-gray-600">{r.description}</div>
                      <div className="text-xs text-gray-500">Type: {r.type}</div>
                    </a>
                  </Link>
                </li>
              );
            })}
          </ul>

          {/* Pagination */}
          {total > limit && (
            <div className="mt-4 flex items-center justify-between">
              <div className="text-sm text-gray-600">
                Showing page {page} of {Math.ceil(total / limit)}
              </div>
              <div className="space-x-2">
                <button
                  onClick={() => setPage(p => Math.max(1, p - 1))}
                  disabled={page === 1}
                  className="px-3 py-1 border rounded disabled:opacity-50"
                  aria-label="Previous page"
                >
                  Prev
                </button>
                <button
                  onClick={() => setPage(p => Math.min(Math.ceil(total / limit), p + 1))}
                  disabled={page >= Math.ceil(total / limit)}
                  className="px-3 py-1 border rounded disabled:opacity-50"
                  aria-label="Next page"
                >
                  Next
                </button>
              </div>
            </div>
          )}
        </div>
      )}
    </div>
  );
};

'use client';

import { useCallback, useState, useRef } from 'react';

export interface SearchError {
  message: string;
  code?: string;
  statusCode?: number;
}

export function useSearch() {
  const [results, setResults] = useState<any[]>([]);
  const [total, setTotal] = useState(0);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<SearchError | null>(null);
  const abortRef = useRef<AbortController | null>(null);

  const search = useCallback(async (query: string, type: string = 'all', page = 1, limit = 10) => {
    // Abort previous request
    if (abortRef.current) abortRef.current.abort();

    // Clear empty queries
    if (!query || query.trim().length === 0) {
      setResults([]);
      setTotal(0);
      setError(null);
      return;
    }

    setLoading(true);
    setError(null);
    const ctrl = new AbortController();
    abortRef.current = ctrl;

    const startTime = performance.now();

    try {
      const params = new URLSearchParams();
      params.set('query', query);
      if (type && type !== 'all') params.set('type', type);
      params.set('page', String(page));
      params.set('limit', String(limit));

      const res = await fetch(`/api/search?${params.toString()}`, {
        signal: ctrl.signal,
        headers: {
          'Content-Type': 'application/json',
        },
      });

      // Handle various error responses
      if (!res.ok) {
        let errorMessage = `Search failed with status ${res.status}`;
        let responseData: any = null;

        try {
          responseData = await res.json();
          if (responseData?.message) {
            errorMessage = responseData.message;
          }
        } catch {
          // If response is not JSON, use status text
          errorMessage = res.statusText || errorMessage;
        }

        throw {
          message: errorMessage,
          code: 'SEARCH_ERROR',
          statusCode: res.status,
        };
      }

      const data = await res.json();

      // Validate response structure
      if (!data || typeof data !== 'object') {
        throw {
          message: 'Invalid search response format',
          code: 'INVALID_RESPONSE',
        };
      }

      setResults(data.results || []);
      setTotal(data.total || 0);

      const duration = performance.now() - startTime;
      console.debug(`Search completed in ${duration.toFixed(2)}ms:`, {
        query,
        type,
        resultCount: data.results?.length || 0,
        total: data.total || 0,
      });
    } catch (err) {
      // Handle abort signal (user cancelled)
      if (err instanceof Error && err.name === 'AbortError') {
        console.debug('Search request was cancelled');
        return;
      }

      // Handle timeout
      if (err instanceof Error && err.name === 'TimeoutError') {
        setError({
          message: 'Search request timed out. Please try again.',
          code: 'TIMEOUT',
        });
      } else if (typeof err === 'object' && err !== null && 'code' in err) {
        // Handle structured errors from our throw above
        setError(err as SearchError);
      } else {
        // Handle generic errors
        const message = err instanceof Error ? err.message : 'Search failed. Please try again.';
        setError({
          message,
          code: 'UNKNOWN',
        });
        console.error('Search error:', err);
      }

      setResults([]);
      setTotal(0);
    } finally {
      setLoading(false);
    }
  }, []);

  /**
   * Clear current search and errors
   */
  const clearSearch = useCallback(() => {
    setResults([]);
    setTotal(0);
    setError(null);
    if (abortRef.current) {
      abortRef.current.abort();
    }
  }, []);

  return {
    results,
    total,
    loading,
    error,
    search,
    clearSearch,
  } as const;
}

